'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { useAuthStore } from '@/lib/store';
import { supabase } from '@/lib/supabase';
import Sidebar from '@/components/Sidebar';
import { FileSpreadsheet, Download, Filter, Users, Award, FolderGit2, CheckCircle, XCircle, ChevronDown, Printer } from 'lucide-react';

interface StudentGrade {
  student_id: string;
  student_name: string;
  student_role: string;
  repo_id: string;
  repo_name: string;
  repo_language: string | null;
  score: number;
  feedback: string | null;
  teacher_name: string;
  graded_at: string;
}

export default function ReportsPage() {
  const { user, profile } = useAuthStore();
  const router = useRouter();
  const [grades, setGrades] = useState<StudentGrade[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterStatus, setFilterStatus] = useState<'all' | 'passed' | 'failed'>('all');
  const [sortBy, setSortBy] = useState<'name' | 'score' | 'date'>('name');

  const isTeacher = profile?.role === 'docente' || profile?.role === 'superadministrador';

  useEffect(() => {
    if (!user) { router.replace('/login'); return; }
    if (!isTeacher) { router.replace('/dashboard'); return; }
    loadGrades();
  }, [user, profile, router]);

  const loadGrades = async () => {
    setLoading(true);

    // Get all grades
    const { data: gradesData, error } = await supabase
      .from('grades')
      .select('*')
      .order('created_at', { ascending: false });

    if (error || !gradesData) { setLoading(false); return; }

    // Get all referenced user IDs (students + teachers)
    const allUserIds = [...new Set([
      ...gradesData.map(g => g.student_id),
      ...gradesData.map(g => g.teacher_id).filter(Boolean),
    ])];

    const { data: profiles } = await supabase
      .from('profiles')
      .select('id, full_name, role')
      .in('id', allUserIds);

    const profileMap: Record<string, { name: string; role: string }> = {};
    profiles?.forEach(p => { profileMap[p.id] = { name: p.full_name || 'Sin nombre', role: p.role }; });

    // Get all referenced repo IDs
    const repoIds = [...new Set(gradesData.map(g => g.repo_id))];
    const { data: repos } = await supabase
      .from('repositories')
      .select('id, name, primary_language')
      .in('id', repoIds);

    const repoMap: Record<string, { name: string; language: string | null }> = {};
    repos?.forEach(r => { repoMap[r.id] = { name: r.name, language: r.primary_language }; });

    const mapped: StudentGrade[] = gradesData.map(g => ({
      student_id: g.student_id,
      student_name: profileMap[g.student_id]?.name || 'Desconocido',
      student_role: profileMap[g.student_id]?.role || 'estudiante',
      repo_id: g.repo_id,
      repo_name: repoMap[g.repo_id]?.name || 'Repo eliminado',
      repo_language: repoMap[g.repo_id]?.language || null,
      score: g.score,
      feedback: g.feedback,
      teacher_name: profileMap[g.teacher_id]?.name || 'Docente',
      graded_at: g.created_at,
    }));

    setGrades(mapped);
    setLoading(false);
  };

  // Filtered & sorted data
  const filtered = grades.filter(g => {
    if (filterStatus === 'passed') return g.score >= 60;
    if (filterStatus === 'failed') return g.score < 60;
    return true;
  });

  const sorted = [...filtered].sort((a, b) => {
    if (sortBy === 'name') return a.student_name.localeCompare(b.student_name);
    if (sortBy === 'score') return b.score - a.score;
    if (sortBy === 'date') return new Date(b.graded_at).getTime() - new Date(a.graded_at).getTime();
    return 0;
  });

  // Stats
  const totalStudents = new Set(grades.map(g => g.student_id)).size;
  const avgScore = grades.length > 0 ? Math.round(grades.reduce((s, g) => s + g.score, 0) / grades.length) : 0;
  const passedCount = grades.filter(g => g.score >= 60).length;
  const failedCount = grades.filter(g => g.score < 60).length;

  // Export CSV
  const exportCSV = () => {
    const header = 'Estudiante,Repositorio,Lenguaje,Puntuación,Estado,Evaluador,Feedback,Fecha';
    const rows = sorted.map(g => {
      const status = g.score >= 60 ? 'Aprobado' : 'Reprobado';
      const date = new Date(g.graded_at).toLocaleDateString('es-VE');
      const feedback = (g.feedback || '').replace(/"/g, '""');
      return `"${g.student_name}","${g.repo_name}","${g.repo_language || 'N/A'}",${g.score},"${status}","${g.teacher_name}","${feedback}","${date}"`;
    });

    const csv = '\uFEFF' + [header, ...rows].join('\n'); // BOM for Excel UTF-8
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `reporte_calificaciones_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // Print-friendly version
  const handlePrint = () => {
    window.print();
  };

  if (!user || !isTeacher) return null;

  return (
    <>
      <Sidebar />
      <div className="main-content">
        <div className="animate-in">
          {/* Header */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', flexWrap: 'wrap', gap: '1rem' }}>
            <div>
              <p style={{ fontSize: '0.8rem', color: 'var(--secondary)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.25rem' }}>
                Panel Docente
              </p>
              <h1 style={{ fontSize: '2rem', fontWeight: 800, letterSpacing: '-0.02em' }}>Reportes Académicos</h1>
            </div>
            <div style={{ display: 'flex', gap: '0.75rem' }}>
              <button onClick={handlePrint} className="btn-ghost" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', border: '1px solid var(--outline-variant)' }}>
                <Printer size={16} /> Imprimir
              </button>
              <button onClick={exportCSV} className="btn-primary" disabled={sorted.length === 0} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <Download size={16} /> Exportar CSV
              </button>
            </div>
          </div>

          {/* Stats Cards */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '1rem', marginBottom: '1.5rem' }}>
            <div className="card" style={{ textAlign: 'center', padding: '1.25rem' }}>
              <Users size={22} color="var(--primary)" style={{ margin: '0 auto 0.5rem' }} />
              <p style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--primary)', lineHeight: 1 }}>{totalStudents}</p>
              <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>Estudiantes Evaluados</p>
            </div>
            <div className="card" style={{ textAlign: 'center', padding: '1.25rem' }}>
              <Award size={22} color="var(--secondary)" style={{ margin: '0 auto 0.5rem' }} />
              <p style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--secondary)', lineHeight: 1 }}>{avgScore}<span style={{ fontSize: '0.9rem', fontWeight: 400 }}>/100</span></p>
              <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>Promedio General</p>
            </div>
            <div className="card" style={{ textAlign: 'center', padding: '1.25rem' }}>
              <CheckCircle size={22} color="var(--tertiary)" style={{ margin: '0 auto 0.5rem' }} />
              <p style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--tertiary)', lineHeight: 1 }}>{passedCount}</p>
              <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>Aprobados (≥60)</p>
            </div>
            <div className="card" style={{ textAlign: 'center', padding: '1.25rem' }}>
              <XCircle size={22} color="var(--error)" style={{ margin: '0 auto 0.5rem' }} />
              <p style={{ fontSize: '2rem', fontWeight: 800, color: 'var(--error)', lineHeight: 1 }}>{failedCount}</p>
              <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>Reprobados (&lt;60)</p>
            </div>
          </div>

          {/* Filters */}
          <div style={{ display: 'flex', gap: '0.75rem', marginBottom: '1.5rem', flexWrap: 'wrap', alignItems: 'center' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <Filter size={16} color="var(--on-surface-variant)" />
              <span style={{ fontSize: '0.8rem', fontWeight: 600, color: 'var(--on-surface-variant)' }}>Filtrar:</span>
            </div>
            {[
              { key: 'all' as const, label: 'Todos', count: grades.length },
              { key: 'passed' as const, label: 'Aprobados', count: passedCount },
              { key: 'failed' as const, label: 'Reprobados', count: failedCount },
            ].map(f => (
              <button
                key={f.key}
                onClick={() => setFilterStatus(f.key)}
                style={{
                  padding: '0.35rem 0.75rem', borderRadius: '9999px', fontSize: '0.8rem',
                  fontWeight: 600, fontFamily: 'Inter', cursor: 'pointer',
                  background: filterStatus === f.key ? 'rgba(109,221,255,0.12)' : 'transparent',
                  border: filterStatus === f.key ? '1px solid rgba(109,221,255,0.3)' : '1px solid rgba(72,72,73,0.2)',
                  color: filterStatus === f.key ? 'var(--primary)' : 'var(--on-surface-variant)',
                  transition: 'all 0.15s ease',
                }}
              >
                {f.label} ({f.count})
              </button>
            ))}

            <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <span style={{ fontSize: '0.8rem', color: 'var(--on-surface-variant)' }}>Ordenar:</span>
              <select
                className="input-field"
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value as 'name' | 'score' | 'date')}
                style={{ padding: '0.35rem 0.75rem', fontSize: '0.8rem', width: 'auto' }}
              >
                <option value="name">Nombre</option>
                <option value="score">Puntuación</option>
                <option value="date">Fecha</option>
              </select>
            </div>
          </div>

          {/* Grades Table */}
          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '4rem' }}>
              <div className="spinner" />
            </div>
          ) : sorted.length === 0 ? (
            <div className="empty-state">
              <FileSpreadsheet size={48} strokeWidth={1} />
              <h3 style={{ fontSize: '1.1rem', fontWeight: 600 }}>Sin calificaciones registradas</h3>
              <p style={{ fontSize: '0.85rem' }}>Las calificaciones asignadas desde los repositorios aparecerán aquí.</p>
            </div>
          ) : (
            <div style={{ background: 'var(--surface-container)', border: '1px solid rgba(72,72,73,0.15)', borderRadius: '0.75rem', overflow: 'hidden' }}>
              <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' }}>
                  <thead>
                    <tr style={{ borderBottom: '1px solid rgba(72,72,73,0.15)', background: 'rgba(72,72,73,0.05)' }}>
                      <th style={{ padding: '0.875rem 1rem', textAlign: 'left', fontWeight: 600, color: 'var(--on-surface-variant)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Estudiante</th>
                      <th style={{ padding: '0.875rem 1rem', textAlign: 'left', fontWeight: 600, color: 'var(--on-surface-variant)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Repositorio</th>
                      <th style={{ padding: '0.875rem 1rem', textAlign: 'center', fontWeight: 600, color: 'var(--on-surface-variant)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Puntuación</th>
                      <th style={{ padding: '0.875rem 1rem', textAlign: 'center', fontWeight: 600, color: 'var(--on-surface-variant)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Estado</th>
                      <th style={{ padding: '0.875rem 1rem', textAlign: 'left', fontWeight: 600, color: 'var(--on-surface-variant)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Feedback</th>
                      <th style={{ padding: '0.875rem 1rem', textAlign: 'right', fontWeight: 600, color: 'var(--on-surface-variant)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Fecha</th>
                    </tr>
                  </thead>
                  <tbody>
                    {sorted.map((g, i) => (
                      <tr
                        key={`${g.student_id}-${g.repo_id}-${i}`}
                        style={{
                          borderBottom: '1px solid rgba(72,72,73,0.08)',
                          transition: 'background 0.15s',
                        }}
                        onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(255,255,255,0.02)'; }}
                        onMouseLeave={(e) => { e.currentTarget.style.background = 'transparent'; }}
                      >
                        <td style={{ padding: '0.875rem 1rem' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <div style={{
                              width: 30, height: 30, borderRadius: '50%',
                              background: 'rgba(193,128,255,0.15)',
                              display: 'flex', alignItems: 'center', justifyContent: 'center',
                              fontSize: '0.75rem', fontWeight: 700, color: 'var(--secondary)', flexShrink: 0,
                            }}>
                              {g.student_name[0]?.toUpperCase()}
                            </div>
                            <span style={{ fontWeight: 600 }}>{g.student_name}</span>
                          </div>
                        </td>
                        <td style={{ padding: '0.875rem 1rem' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <FolderGit2 size={14} color="var(--primary)" />
                            <span>{g.repo_name}</span>
                            {g.repo_language && (
                              <span style={{ fontSize: '0.65rem', padding: '0.1rem 0.35rem', borderRadius: '0.25rem', background: 'rgba(109,221,255,0.1)', color: 'var(--primary)' }}>
                                {g.repo_language}
                              </span>
                            )}
                          </div>
                        </td>
                        <td style={{ padding: '0.875rem 1rem', textAlign: 'center' }}>
                          <span style={{
                            fontWeight: 800, fontSize: '1.1rem',
                            color: g.score >= 80 ? 'var(--tertiary)' : g.score >= 60 ? 'var(--primary)' : g.score >= 40 ? '#ffb74d' : 'var(--error)',
                          }}>
                            {g.score}
                          </span>
                        </td>
                        <td style={{ padding: '0.875rem 1rem', textAlign: 'center' }}>
                          <span style={{
                            fontSize: '0.75rem', fontWeight: 600,
                            padding: '0.2rem 0.6rem', borderRadius: '9999px',
                            background: g.score >= 60 ? 'rgba(155,255,206,0.1)' : 'rgba(255,113,108,0.1)',
                            color: g.score >= 60 ? 'var(--tertiary)' : 'var(--error)',
                          }}>
                            {g.score >= 60 ? 'Aprobado' : 'Reprobado'}
                          </span>
                        </td>
                        <td style={{ padding: '0.875rem 1rem', maxWidth: '220px' }}>
                          <p style={{
                            fontSize: '0.8rem', color: 'var(--on-surface-variant)',
                            overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                            margin: 0,
                          }}>
                            {g.feedback || '—'}
                          </p>
                        </td>
                        <td style={{ padding: '0.875rem 1rem', textAlign: 'right', color: 'var(--on-surface-variant)', fontSize: '0.8rem' }}>
                          {new Date(g.graded_at).toLocaleDateString('es-VE', { day: 'numeric', month: 'short' })}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}

'use client';

import { useEffect, useState, use } from 'react';
import { useRouter } from 'next/navigation';
import { useAuthStore } from '@/lib/store';
import { supabase } from '@/lib/supabase';
import Sidebar from '@/components/Sidebar';
import Link from 'next/link';
import { ArrowLeft, FileCode, Plus, MessageSquare, Play, Square, Terminal, X, Loader2 } from 'lucide-react';
import { Highlight, themes } from 'prism-react-renderer';

interface PageProps {
  params: Promise<{ id: string; path: string[] }>;
}

// Language mapping for Piston API
const RUNNABLE_LANGUAGES: Record<string, { language: string; version: string; prismLang: string }> = {
  'js': { language: 'javascript', version: '18.15.0', prismLang: 'javascript' },
  'javascript': { language: 'javascript', version: '18.15.0', prismLang: 'javascript' },
  'ts': { language: 'typescript', version: '5.0.3', prismLang: 'typescript' },
  'typescript': { language: 'typescript', version: '5.0.3', prismLang: 'typescript' },
  'py': { language: 'python', version: '3.10.0', prismLang: 'python' },
  'python': { language: 'python', version: '3.10.0', prismLang: 'python' },
  'java': { language: 'java', version: '15.0.2', prismLang: 'java' },
  'c': { language: 'c', version: '10.2.0', prismLang: 'c' },
  'cpp': { language: 'c++', version: '10.2.0', prismLang: 'cpp' },
  'cs': { language: 'csharp', version: '6.12.0', prismLang: 'csharp' },
  'go': { language: 'go', version: '1.16.2', prismLang: 'go' },
  'rs': { language: 'rust', version: '1.68.2', prismLang: 'rust' },
  'rb': { language: 'ruby', version: '3.0.1', prismLang: 'ruby' },
  'php': { language: 'php', version: '8.2.3', prismLang: 'php' },
  'sh': { language: 'bash', version: '5.2.0', prismLang: 'bash' },
  'bash': { language: 'bash', version: '5.2.0', prismLang: 'bash' },
};

function getFileExtension(path: string): string {
  const parts = path.split('.');
  return parts.length > 1 ? parts[parts.length - 1].toLowerCase() : '';
}

function getPrismLanguage(ext: string): string {
  const map: Record<string, string> = {
    js: 'javascript', jsx: 'jsx', ts: 'typescript', tsx: 'tsx',
    py: 'python', java: 'java', c: 'c', cpp: 'cpp', cs: 'csharp',
    go: 'go', rs: 'rust', rb: 'ruby', php: 'php', html: 'markup',
    css: 'css', json: 'json', md: 'markdown', sql: 'sql',
    sh: 'bash', bash: 'bash', yaml: 'yaml', yml: 'yaml',
    xml: 'markup', svg: 'markup', vue: 'markup', svelte: 'markup',
  };
  return map[ext] || 'typescript';
}

export default function CodeViewerPage(props: PageProps) {
  const params = use(props.params);
  const { user, profile } = useAuthStore();
  const router = useRouter();

  const [fileContent, setFileContent] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [activeLine, setActiveLine] = useState<number | null>(null);
  const [commentingLine, setCommentingLine] = useState<number | null>(null);
  const [commentText, setCommentText] = useState('');
  const [comments, setComments] = useState<Record<number, { id: string; author: string; content: string }[]>>({});

  // Code execution state
  const [isRunning, setIsRunning] = useState(false);
  const [showConsole, setShowConsole] = useState(false);
  const [consoleOutput, setConsoleOutput] = useState('');
  const [executionTime, setExecutionTime] = useState<number | null>(null);

  const filePath = params.path.join('/');
  const ext = getFileExtension(filePath);
  const prismLang = getPrismLanguage(ext);
  const isRunnable = RUNNABLE_LANGUAGES[ext] !== undefined;
  const isDocente = profile?.role === 'docente' || profile?.role === 'superadministrador';

  useEffect(() => {
    if (!user) { router.replace('/login'); return; }
    loadFile();
    loadComments();
  }, [user, router, params.id, filePath]);

  const loadFile = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('repository_files')
      .select('content')
      .eq('repo_id', params.id)
      .eq('file_path', filePath)
      .single();

    if (data) {
      setFileContent(data.content || '// Archivo vacío');
    } else {
      setFileContent(`// Error cargando archivo: ${error?.message || 'No encontrado'}`);
    }
    setLoading(false);
  };

  const loadComments = async () => {
    const { data } = await supabase
      .from('code_comments')
      .select('id, line_number, content, author_id')
      .eq('repo_id', params.id)
      .eq('file_path', filePath)
      .order('created_at', { ascending: true });

    if (!data || data.length === 0) return;

    // Fetch author names
    const authorIds = [...new Set(data.map(c => c.author_id))];
    const { data: profiles } = await supabase
      .from('profiles')
      .select('id, full_name')
      .in('id', authorIds);

    const nameMap: Record<string, string> = {};
    profiles?.forEach(p => { nameMap[p.id] = p.full_name || 'Usuario'; });

    const grouped: Record<number, { id: string; author: string; content: string }[]> = {};
    data.forEach(c => {
      if (!grouped[c.line_number]) grouped[c.line_number] = [];
      grouped[c.line_number].push({
        id: c.id,
        author: nameMap[c.author_id] || 'Docente',
        content: c.content,
      });
    });
    setComments(grouped);
  };

  const handleAddComment = async () => {
    if (!commentText.trim() || commentingLine === null || !user) return;

    const { error } = await supabase.from('code_comments').insert({
      repo_id: params.id,
      file_path: filePath,
      line_number: commentingLine,
      content: commentText.trim(),
      author_id: user.id,
    });

    if (!error) {
      setCommentText('');
      setCommentingLine(null);
      loadComments();
    }
  };

  // Execute code via Piston API
  const handleRunCode = async () => {
    if (!isRunnable || isRunning) return;
    const langConfig = RUNNABLE_LANGUAGES[ext];

    setIsRunning(true);
    setShowConsole(true);
    setConsoleOutput('⏳ Ejecutando código...\n');
    setExecutionTime(null);

    const startTime = Date.now();

    try {
      const response = await fetch('https://emkc.org/api/v2/piston/execute', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          language: langConfig.language,
          version: langConfig.version,
          files: [{ name: filePath.split('/').pop() || 'main', content: fileContent }],
          stdin: '',
          args: [],
          run_timeout: 10000, // 10 second timeout
        }),
      });

      const elapsed = Date.now() - startTime;
      setExecutionTime(elapsed);

      if (!response.ok) throw new Error(`API error: ${response.status}`);

      const result = await response.json();

      let output = '';

      // Compile output (for compiled languages)
      if (result.compile && result.compile.stderr) {
        output += `⚠️ Errores de compilación:\n${result.compile.stderr}\n\n`;
      }

      // Runtime output
      if (result.run) {
        if (result.run.stdout) output += result.run.stdout;
        if (result.run.stderr) output += `\n⚠️ stderr:\n${result.run.stderr}`;
        if (result.run.signal === 'SIGKILL') output += '\n⏰ Ejecución cancelada: tiempo excedido (10s)';
        if (result.run.code !== 0 && !result.run.stderr) output += `\n❌ Proceso terminó con código: ${result.run.code}`;
      }

      setConsoleOutput(output || '✅ Ejecución completada sin salida.');

    } catch (err: any) {
      setExecutionTime(Date.now() - startTime);
      setConsoleOutput(`❌ Error de ejecución: ${err.message}\n\nAsegúrate de tener conexión a internet.`);
    } finally {
      setIsRunning(false);
    }
  };

  if (!user) return null;

  return (
    <>
      <Sidebar />
      <div className="main-content">
        <div className="animate-in">
          <Link href={`/repos/${params.id}`} style={{ display: 'inline-flex', alignItems: 'center', gap: '0.5rem', color: 'var(--on-surface-variant)', textDecoration: 'none', marginBottom: '1.5rem', fontSize: '0.9rem', fontWeight: 500 }}>
            <ArrowLeft size={16} /> Volver al Repositorio
          </Link>

          {/* Header de Archivo + Run Button */}
          <div style={{
            background: 'var(--surface-container-high)',
            border: '1px solid rgba(72, 72, 73, 0.15)',
            borderRadius: '0.75rem 0.75rem 0 0',
            padding: '0.75rem 1.25rem',
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
              <FileCode size={20} color="var(--primary)" />
              <h2 style={{ fontFamily: 'JetBrains Mono, monospace', fontSize: '0.95rem', fontWeight: 600, margin: 0 }}>
                {filePath}
              </h2>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              {isRunnable && (
                <button
                  onClick={handleRunCode}
                  disabled={isRunning || loading}
                  style={{
                    display: 'flex', alignItems: 'center', gap: '0.4rem',
                    padding: '0.4rem 0.9rem',
                    borderRadius: '0.5rem',
                    border: 'none',
                    cursor: isRunning ? 'wait' : 'pointer',
                    background: isRunning ? 'rgba(155,255,206,0.15)' : 'rgba(155,255,206,0.1)',
                    color: 'var(--tertiary)',
                    fontSize: '0.8rem',
                    fontWeight: 600,
                    fontFamily: 'Inter, sans-serif',
                    transition: 'all 0.2s ease',
                  }}
                  onMouseEnter={(e) => { if (!isRunning) e.currentTarget.style.background = 'rgba(155,255,206,0.2)'; }}
                  onMouseLeave={(e) => { if (!isRunning) e.currentTarget.style.background = 'rgba(155,255,206,0.1)'; }}
                >
                  {isRunning ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : <Play size={14} />}
                  {isRunning ? 'Ejecutando...' : 'Ejecutar'}
                </button>
              )}
              {showConsole && (
                <button
                  onClick={() => setShowConsole(false)}
                  style={{
                    background: 'none', border: 'none', cursor: 'pointer',
                    color: 'var(--on-surface-variant)', padding: '0.3rem',
                  }}
                  title="Cerrar consola"
                >
                  <X size={16} />
                </button>
              )}
            </div>
          </div>

          {/* Visor de Código */}
          <div style={{
            background: '#131314',
            border: '1px solid rgba(72, 72, 73, 0.15)',
            borderTop: 'none',
            borderRadius: showConsole ? '0' : '0 0 0.75rem 0.75rem',
            overflowX: 'auto',
            padding: '1rem 0',
          }}>
            {loading ? (
              <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
                <div className="spinner" />
              </div>
            ) : (
              <Highlight theme={themes.palenight} code={fileContent} language={prismLang}>
                {({ className, style, tokens, getLineProps, getTokenProps }) => (
                  <pre className={className} style={{ ...style, background: 'transparent', margin: 0, padding: 0, fontSize: '0.85rem' }}>
                    {tokens.map((line, i) => {
                      const lineNumber = i + 1;
                      const lineComments = comments[lineNumber];
                      const hasComments = lineComments && lineComments.length > 0;
                      const isHovered = activeLine === lineNumber;
                      const isCommenting = commentingLine === lineNumber;

                      return (
                        <div key={i} style={{ display: 'flex', flexDirection: 'column' }}>
                          <div
                            {...getLineProps({ line, key: i })}
                            onMouseEnter={() => setActiveLine(lineNumber)}
                            onMouseLeave={() => setActiveLine(null)}
                            style={{
                              display: 'flex', position: 'relative',
                              background: hasComments ? 'rgba(109, 221, 255, 0.05)' : isHovered ? 'rgba(255, 255, 255, 0.03)' : 'transparent',
                              padding: '0 1rem',
                            }}
                          >
                            <span style={{
                              width: '40px', textAlign: 'right', paddingRight: '1rem',
                              color: 'var(--outline-variant)', userSelect: 'none',
                              fontFamily: 'JetBrains Mono, monospace',
                            }}>
                              {lineNumber}
                            </span>

                            <div style={{ flex: 1, fontFamily: 'JetBrains Mono, monospace' }}>
                              {line.map((token, key) => (
                                <span key={key} {...getTokenProps({ token, key })} />
                              ))}
                            </div>

                            {isDocente && isHovered && !isCommenting && (
                              <button
                                onClick={() => setCommentingLine(lineNumber)}
                                style={{
                                  position: 'absolute', left: '10px',
                                  background: 'var(--primary)', color: '#002c37',
                                  border: 'none', borderRadius: '4px',
                                  width: '20px', height: '20px', cursor: 'pointer',
                                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                                  zIndex: 10,
                                }}
                              >
                                <Plus size={14} />
                              </button>
                            )}
                          </div>

                          {(hasComments || isCommenting) && (
                            <div style={{ background: 'rgba(26, 25, 27, 0.5)', borderTop: '1px solid rgba(72, 72, 73, 0.1)', borderBottom: '1px solid rgba(72, 72, 73, 0.1)', padding: '1rem 1rem 1rem 3.5rem' }}>
                              {lineComments?.map((c) => (
                                <div key={c.id} style={{ background: 'var(--surface-container-high)', border: '1px solid rgba(109,221,255,0.2)', padding: '0.8rem 1rem', borderRadius: '0.5rem', marginBottom: '0.5rem', display: 'flex', gap: '0.75rem', alignItems: 'flex-start' }}>
                                  <MessageSquare size={16} color="var(--primary)" style={{ marginTop: '2px' }} />
                                  <div>
                                    <span style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--primary)', display: 'block', marginBottom: '0.2rem' }}>{c.author}</span>
                                    <p style={{ margin: 0, fontSize: '0.85rem', color: 'var(--on-surface)', lineHeight: 1.5 }}>{c.content}</p>
                                  </div>
                                </div>
                              ))}

                              {isCommenting && (
                                <div style={{ marginTop: '0.5rem' }}>
                                  <textarea
                                    className="input-field"
                                    placeholder="Escribe tu observación sobre esta línea de código..."
                                    value={commentText}
                                    onChange={(e) => setCommentText(e.target.value)}
                                    rows={3}
                                    style={{ marginBottom: '0.5rem', resize: 'vertical' }}
                                  />
                                  <div style={{ display: 'flex', gap: '0.5rem', justifyContent: 'flex-end' }}>
                                    <button className="btn-ghost" onClick={() => { setCommentingLine(null); setCommentText(''); }} style={{ padding: '0.4rem 0.8rem', fontSize: '0.8rem' }}>
                                      Cancelar
                                    </button>
                                    <button className="btn-primary" onClick={handleAddComment} style={{ padding: '0.4rem 0.8rem', fontSize: '0.8rem' }}>
                                      Dejar Comentario
                                    </button>
                                  </div>
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </pre>
                )}
              </Highlight>
            )}
          </div>

          {/* Console Output Panel */}
          {showConsole && (
            <div style={{
              background: '#0d0d0e',
              border: '1px solid rgba(72, 72, 73, 0.15)',
              borderTop: '1px solid rgba(155,255,206,0.2)',
              borderRadius: '0 0 0.75rem 0.75rem',
              overflow: 'hidden',
            }}>
              <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '0.5rem 1rem',
                background: 'rgba(155,255,206,0.05)',
                borderBottom: '1px solid rgba(72, 72, 73, 0.1)',
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.75rem', fontWeight: 600, color: 'var(--tertiary)' }}>
                  <Terminal size={14} />
                  Consola de Salida
                  {isRunning && <span style={{ color: 'var(--on-surface-variant)' }}>Ejecutando...</span>}
                </div>
                {executionTime !== null && (
                  <span style={{ fontSize: '0.7rem', color: 'var(--on-surface-variant)' }}>
                    ⏱ {executionTime}ms
                  </span>
                )}
              </div>
              <pre style={{
                margin: 0,
                padding: '1rem',
                fontFamily: 'JetBrains Mono, monospace',
                fontSize: '0.8rem',
                color: 'var(--on-surface)',
                lineHeight: 1.7,
                maxHeight: '250px',
                overflowY: 'auto',
                whiteSpace: 'pre-wrap',
                wordBreak: 'break-word',
              }}>
                {consoleOutput}
              </pre>
            </div>
          )}
        </div>
      </div>
    </>
  );
}

'use client';

import { useEffect, useState, useCallback, useRef } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { useAuthStore } from '@/lib/store';
import { supabase } from '@/lib/supabase';
import Sidebar from '@/components/Sidebar';
import GradingPanel from '@/components/GradingPanel';
import CollaboratorsPanel from '@/components/CollaboratorsPanel';
import { FolderGit2, ArrowLeft, Terminal, FileCode, MessageSquare, Upload, X, Trash2, Check, Loader2 } from 'lucide-react';
import Link from 'next/link';
import CodeSandbox from '@/components/CodeSandbox';

interface RepoDetails {
  id: string;
  name: string;
  description: string | null;
  primary_language: string | null;
  owner_id: string;
  created_at: string;
}

interface RepoFile {
  id: string;
  repo_id: string;
  path: string;
  content: string | null;
  created_at: string;
}

interface CodeComment {
  id: string;
  file_id: string;
  line_number: number;
  author_id: string;
  content: string;
  created_at: string;
  author_name?: string;
}

// Detect language from file extension for syntax highlighting
function getLanguage(filename: string): string {
  const ext = filename.split('.').pop()?.toLowerCase() || '';
  const langMap: Record<string, string> = {
    ts: 'typescript', tsx: 'tsx', js: 'javascript', jsx: 'jsx',
    py: 'python', java: 'java', c: 'c', cpp: 'cpp', cs: 'csharp',
    go: 'go', rs: 'rust', php: 'php', rb: 'ruby', swift: 'swift',
    html: 'html', css: 'css', scss: 'css', json: 'json', md: 'markdown',
    sql: 'sql', sh: 'bash', yaml: 'yaml', yml: 'yaml', xml: 'xml',
  };
  return langMap[ext] || 'javascript';
}

export default function RepositoryDetailsPage() {
  const { user, profile } = useAuthStore();
  const router = useRouter();
  const params = useParams();
  const id = params.id as string;

  const [repo, setRepo] = useState<RepoDetails | null>(null);
  const [loading, setLoading] = useState(true);

  // File explorer state
  const [files, setFiles] = useState<RepoFile[]>([]);
  const [filesLoading, setFilesLoading] = useState(true);
  const [selectedFile, setSelectedFile] = useState<RepoFile | null>(null);

  // Comment state
  const [commentingLine, setCommentingLine] = useState<number | null>(null);
  const [commentText, setCommentText] = useState('');
  const [comments, setComments] = useState<CodeComment[]>([]);
  const [commentSaving, setCommentSaving] = useState(false);

  const [editContent, setEditContent] = useState('');
  const [autoSaveStatus, setAutoSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
  const autoSaveTimerRef = useRef<NodeJS.Timeout | null>(null);

  // File creation modal
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [newFilePath, setNewFilePath] = useState('');
  const [newFileContent, setNewFileContent] = useState('');
  const [uploadLoading, setUploadLoading] = useState(false);

  // Load repo details
  const loadRepo = useCallback(async () => {
    setLoading(true);
    const { data } = await supabase.from('repositories').select('*').eq('id', id).single();
    if (data) setRepo(data);
    setLoading(false);
  }, [id]);

  // Load files for this repo
  const loadFiles = useCallback(async () => {
    setFilesLoading(true);
    const { data } = await supabase
      .from('repository_files')
      .select('*')
      .eq('repo_id', id)
      .order('path', { ascending: true });
    setFiles(data || []);
    setFilesLoading(false);
  }, [id]);

  // Load comments for a specific file
  const loadComments = useCallback(async (fileId: string) => {
    const { data } = await supabase
      .from('code_comments')
      .select('*')
      .eq('file_id', fileId)
      .order('created_at', { ascending: true });

    if (!data || data.length === 0) {
      setComments([]);
      return;
    }

    // Fetch author names
    const authorIds = [...new Set(data.map((c) => c.author_id))];
    const { data: profiles } = await supabase
      .from('profiles')
      .select('id, full_name')
      .in('id', authorIds);
    const nameMap: Record<string, string> = {};
    profiles?.forEach((p) => { nameMap[p.id] = p.full_name || 'Anónimo'; });

    setComments(data.map((c) => ({ ...c, author_name: nameMap[c.author_id] || 'Anónimo' })));
  }, []);

  // Initial load
  useEffect(() => {
    if (!user) {
      router.replace('/login');
      return;
    }
    loadRepo();
    loadFiles();
  }, [user, router, loadRepo, loadFiles]);

  // Load comments when file changes & subscribe to realtime
  useEffect(() => {
    if (!selectedFile) {
      setComments([]);
      return;
    }

    loadComments(selectedFile.id);

    // Realtime subscription for new comments on this file
    const channel = supabase
      .channel(`comments-${selectedFile.id}`)
      .on('postgres_changes', {
        event: '*',
        schema: 'public',
        table: 'code_comments',
        filter: `file_id=eq.${selectedFile.id}`,
      }, () => {
        loadComments(selectedFile.id);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [selectedFile, loadComments]);

  // Add a comment to the database
  const handleAddComment = async () => {
    if (!commentText.trim() || commentingLine === null || !selectedFile || !user) return;
    setCommentSaving(true);

    await supabase.from('code_comments').insert({
      file_id: selectedFile.id,
      line_number: commentingLine,
      author_id: user.id,
      content: commentText,
    });

    setCommentText('');
    setCommentingLine(null);
    setCommentSaving(false);
    // Realtime will trigger a reload, but also do it explicitly as fallback
    await loadComments(selectedFile.id);
  };

  // Create a new file in this repo
  const handleCreateFile = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !newFilePath.trim()) return;
    setUploadLoading(true);

    const { error } = await supabase.from('repository_files').insert({
      repo_id: id,
      path: newFilePath.trim(),
      content: newFileContent || '',
    });

    if (error) {
      alert('Error al crear el archivo: ' + error.message);
    } else {
      setShowUploadModal(false);
      setNewFilePath('');
      setNewFileContent('');
      await loadFiles();
    }
    setUploadLoading(false);
  };

  // Delete a file
  const handleDeleteFile = async (fileId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('¿Estás seguro de eliminar este archivo?')) return;
    await supabase.from('repository_files').delete().eq('id', fileId);
    if (selectedFile?.id === fileId) {
      setSelectedFile(null);
      setComments([]);
    }
    await loadFiles();
    setEditContent('');
  };

  if (!user) return null;

  const isDocente = profile?.role === 'docente' || profile?.role === 'superadministrador';
  const isOwner = repo?.owner_id === user.id;
  const canManageFiles = isOwner || profile?.role === 'superadministrador';
  // Any authenticated user can edit code — RLS enforces actual write permissions
  const canEditCode = !!user;

  // Auto-save: debounced save to Supabase
  const performAutoSave = useCallback(async (content: string, fileId: string) => {
    setAutoSaveStatus('saving');
    const { error } = await supabase
      .from('repository_files')
      .update({ content })
      .eq('id', fileId);

    if (error) {
      console.error('[AutoSave] Error:', error.message);
      setAutoSaveStatus('error');
      setTimeout(() => setAutoSaveStatus('idle'), 3000);
    } else {
      // Update local state
      setSelectedFile(prev => prev && prev.id === fileId ? { ...prev, content } : prev);
      setFiles(prev => prev.map(f => f.id === fileId ? { ...f, content } : f));
      setAutoSaveStatus('saved');
      setTimeout(() => setAutoSaveStatus('idle'), 2000);
    }
  }, []);

  const handleInlineEdit = useCallback((newContent: string) => {
    setEditContent(newContent);
    // Clear previous debounce timer
    if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);
    // Set new debounce timer (1.5s after user stops typing)
    if (selectedFile) {
      const fileId = selectedFile.id;
      autoSaveTimerRef.current = setTimeout(() => {
        performAutoSave(newContent, fileId);
      }, 1500);
    }
  }, [selectedFile, performAutoSave]);

  // Initialize edit content when selecting a file
  useEffect(() => {
    if (selectedFile) {
      setEditContent(selectedFile.content || '');
      setAutoSaveStatus('idle');
    }
    return () => {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);
    };
  }, [selectedFile?.id]);

  // Group comments by line number for easy lookup
  const commentsByLine: Record<number, CodeComment[]> = {};
  comments.forEach((c) => {
    if (!commentsByLine[c.line_number]) commentsByLine[c.line_number] = [];
    commentsByLine[c.line_number].push(c);
  });

  // Extract filename from path
  const getFileName = (path: string) => path.split('/').pop() || path;

  return (
    <>
      <Sidebar />
      <div className="main-content" style={{ display: 'flex', flexDirection: 'column', gap: '1rem', minHeight: '100vh' }}>
        <div className="animate-in">
          <Link href="/repos" style={{ display: 'inline-flex', alignItems: 'center', gap: '0.5rem', color: 'var(--on-surface-variant)', textDecoration: 'none', marginBottom: '1.5rem', fontSize: '0.9rem', fontWeight: 500 }}>
            <ArrowLeft size={16} /> Volver a repositorios
          </Link>

          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '4rem 0' }}><div className="spinner"></div></div>
          ) : !repo ? (
            <div className="empty-state">
              <FolderGit2 size={48} style={{ color: 'var(--error)' }} />
              <h3>Repositorio no encontrado</h3>
            </div>
          ) : (
            <>
              {/* Header */}
              <div style={{ marginBottom: '2rem', padding: '2rem', background: 'var(--surface-variant)', borderRadius: '1rem', border: '1px solid rgba(72, 72, 73, 0.15)', display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.5rem' }}>
                    <FolderGit2 size={28} color="var(--primary)" />
                    <h1 style={{ fontSize: '2rem', fontWeight: 800, margin: 0 }}>{repo.name}</h1>
                  </div>
                  {repo.description && <p style={{ fontSize: '1rem', color: 'var(--on-surface-variant)', marginTop: '0.5rem' }}>{repo.description}</p>}
                </div>
                {canManageFiles && (
                  <button className="btn-primary" onClick={() => setShowUploadModal(true)} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flexShrink: 0 }}>
                    <Upload size={16} /> Agregar Archivo
                  </button>
                )}
              </div>

              {/* Grading + Collaborators Panels */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '0.5rem' }}>
                <GradingPanel repoId={repo.id} userId={user!.id} userRole={profile?.role || 'estudiante'} repoOwnerId={repo.owner_id} />
                <CollaboratorsPanel repoId={repo.id} userId={user!.id} userRole={profile?.role || 'estudiante'} repoOwnerId={repo.owner_id} />
              </div>

              {/* Layout: Explorer left, Code right */}
              <div style={{ display: 'grid', gridTemplateColumns: '280px 1fr', gap: '1.5rem', alignItems: 'start' }}>

                {/* File Explorer */}
                <div style={{ background: 'var(--surface-container-high)', border: '1px solid rgba(72, 72, 73, 0.15)', borderRadius: '1rem', overflow: 'hidden' }}>
                  <div style={{ background: 'rgba(72, 72, 73, 0.1)', padding: '1rem 1.5rem', borderBottom: '1px solid rgba(72, 72, 73, 0.15)', display: 'flex', alignItems: 'center', gap: '0.5rem', fontWeight: 600 }}>
                    <Terminal size={18} /> Explorador
                  </div>
                  <div style={{ padding: '0' }}>
                    {filesLoading ? (
                      <div style={{ display: 'flex', justifyContent: 'center', padding: '2rem' }}>
                        <div className="spinner" style={{ width: 24, height: 24 }}></div>
                      </div>
                    ) : files.length === 0 ? (
                      <div style={{ padding: '2rem 1.5rem', textAlign: 'center', color: 'var(--on-surface-variant)', fontSize: '0.85rem' }}>
                        <FileCode size={32} strokeWidth={1} style={{ margin: '0 auto 0.5rem', display: 'block', opacity: 0.5 }} />
                        Sin archivos aún.
                        {canManageFiles && (
                          <button onClick={() => setShowUploadModal(true)} style={{ display: 'block', margin: '0.75rem auto 0', background: 'none', border: 'none', color: 'var(--primary)', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600 }}>
                            + Agregar archivo
                          </button>
                        )}
                      </div>
                    ) : (
                      files.map((file, i) => (
                        <div key={file.id} style={{ borderBottom: i === files.length - 1 ? 'none' : '1px solid rgba(72, 72, 73, 0.1)' }}>
                          <div
                            onClick={() => setSelectedFile(file)}
                            style={{
                              display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                              width: '100%', padding: '0.875rem 1.5rem', border: 'none', cursor: 'pointer',
                              background: selectedFile?.id === file.id ? 'rgba(109, 221, 255, 0.1)' : 'transparent',
                              color: selectedFile?.id === file.id ? 'var(--primary)' : 'var(--on-surface)',
                              fontFamily: 'JetBrains Mono, monospace', fontSize: '0.85rem',
                            }}
                          >
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', overflow: 'hidden' }}>
                              <FileCode size={16} style={{ flexShrink: 0 }} />
                              <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{file.path}</span>
                            </div>
                            {canManageFiles && (
                              <button
                                onClick={(e) => handleDeleteFile(file.id, e)}
                                style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--on-surface-variant)', padding: '0.125rem', flexShrink: 0, opacity: 0.5 }}
                                title="Eliminar archivo"
                              >
                                <Trash2 size={13} />
                              </button>
                            )}
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                </div>

                {/* Code Editor / Viewer */}
                <div style={{ background: 'var(--surface-container-high)', border: '1px solid rgba(72, 72, 73, 0.15)', borderRadius: '1rem', overflow: 'hidden' }}>
                  {selectedFile ? (
                    <>
                      {/* File header with auto-save status */}
                      <div style={{ background: 'rgba(72, 72, 73, 0.1)', padding: '1rem 1.5rem', borderBottom: '1px solid rgba(72, 72, 73, 0.15)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', fontWeight: 600 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                          <FileCode size={18} color="var(--primary)" /> {selectedFile.path}
                          <span style={{ fontSize: '0.7rem', color: 'var(--on-surface-variant)', fontWeight: 400, fontStyle: 'italic' }}>
                            — edición directa con autoguardado
                          </span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                          {autoSaveStatus === 'saving' && (
                            <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', fontSize: '0.75rem', color: 'var(--secondary)', fontWeight: 500 }}>
                              <Loader2 size={13} style={{ animation: 'spin 1s linear infinite' }} /> Guardando...
                            </span>
                          )}
                          {autoSaveStatus === 'saved' && (
                            <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', fontSize: '0.75rem', color: 'var(--tertiary)', fontWeight: 500 }}>
                              <Check size={13} /> Guardado
                            </span>
                          )}
                          {autoSaveStatus === 'error' && (
                            <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', fontSize: '0.75rem', color: 'var(--error)', fontWeight: 500 }}>
                              ⚠ Error al guardar
                            </span>
                          )}
                          {isDocente && (
                            <span style={{ fontSize: '0.68rem', color: 'var(--outline)', background: 'rgba(193,128,255,0.08)', padding: '0.15rem 0.45rem', borderRadius: '0.2rem' }}>
                              Docente
                            </span>
                          )}
                        </div>
                      </div>

                      {/* Always-editable code textarea */}
                      <textarea
                        value={editContent}
                        onChange={(e) => handleInlineEdit(e.target.value)}
                        spellCheck={false}
                        style={{
                          width: '100%',
                          minHeight: '500px',
                          background: '#131314',
                          color: '#e0e0e0',
                          border: 'none',
                          outline: 'none',
                          resize: 'vertical',
                          padding: '1rem 1.5rem',
                          fontFamily: 'JetBrains Mono, monospace',
                          fontSize: '0.85rem',
                          lineHeight: '1.6',
                          tabSize: 2,
                          boxSizing: 'border-box',
                          display: 'block',
                        }}
                        onKeyDown={(e) => {
                          if (e.key === 'Tab') {
                            e.preventDefault();
                            const target = e.target as HTMLTextAreaElement;
                            const start = target.selectionStart;
                            const end = target.selectionEnd;
                            const newValue = editContent.substring(0, start) + '  ' + editContent.substring(end);
                            handleInlineEdit(newValue);
                            requestAnimationFrame(() => {
                              target.selectionStart = target.selectionEnd = start + 2;
                            });
                          }
                          if ((e.ctrlKey || e.metaKey) && e.key === 's') {
                            e.preventDefault();
                            if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);
                            if (selectedFile) performAutoSave(editContent, selectedFile.id);
                          }
                        }}
                        onBlur={() => {
                          if (autoSaveTimerRef.current) {
                            clearTimeout(autoSaveTimerRef.current);
                            if (selectedFile && editContent !== selectedFile.content) {
                              performAutoSave(editContent, selectedFile.id);
                            }
                          }
                        }}
                      />

                      {/* Comments section — visible below editor */}
                      {Object.keys(commentsByLine).length > 0 && (
                        <div style={{ borderTop: '1px solid rgba(72,72,73,0.15)', padding: '1rem 1.5rem', background: 'rgba(26, 25, 27, 0.5)' }}>
                          <h4 style={{ fontSize: '0.8rem', fontWeight: 600, color: 'var(--on-surface-variant)', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                            <MessageSquare size={14} color="var(--primary)" /> Comentarios del Docente
                          </h4>
                          {Object.entries(commentsByLine).map(([line, lineComments]) => (
                            <div key={line} style={{ marginBottom: '0.75rem' }}>
                              <span style={{ fontSize: '0.7rem', color: 'var(--outline)', fontFamily: 'JetBrains Mono, monospace', marginBottom: '0.3rem', display: 'block' }}>
                                Línea {line}
                              </span>
                              {lineComments.map((comment) => (
                                <div key={comment.id} style={{ background: 'var(--surface-container-high)', border: '1px solid rgba(109,221,255,0.2)', padding: '0.65rem 0.85rem', borderRadius: '0.5rem', marginBottom: '0.4rem', display: 'flex', gap: '0.6rem', alignItems: 'flex-start' }}>
                                  <MessageSquare size={14} color="var(--primary)" style={{ marginTop: '2px', flexShrink: 0 }} />
                                  <div>
                                    <span style={{ fontSize: '0.72rem', fontWeight: 600, color: 'var(--primary)', display: 'block', marginBottom: '0.15rem' }}>
                                      {comment.author_name || 'Docente'}
                                    </span>
                                    <p style={{ margin: 0, fontSize: '0.82rem', color: 'var(--on-surface)', lineHeight: 1.5 }}>{comment.content}</p>
                                  </div>
                                </div>
                              ))}
                            </div>
                          ))}
                        </div>
                      )}

                      {/* Docente comment input */}
                      {isDocente && (
                        <div style={{ borderTop: '1px solid rgba(72,72,73,0.15)', padding: '1rem 1.5rem', background: 'rgba(193,128,255,0.03)' }}>
                          <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'flex-start' }}>
                            <div style={{ flex: 1 }}>
                              <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.5rem' }}>
                                <input
                                  className="input-field"
                                  type="number"
                                  min="1"
                                  placeholder="Línea #"
                                  value={commentingLine || ''}
                                  onChange={(e) => setCommentingLine(e.target.value ? Number(e.target.value) : null)}
                                  style={{ width: '80px', fontSize: '0.8rem' }}
                                />
                                <input
                                  className="input-field"
                                  placeholder="Escribe tu observación sobre el código..."
                                  value={commentText}
                                  onChange={(e) => setCommentText(e.target.value)}
                                  style={{ flex: 1, fontSize: '0.8rem' }}
                                  onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleAddComment(); } }}
                                />
                              </div>
                            </div>
                            <button className="btn-primary" onClick={handleAddComment} disabled={commentSaving || !commentText.trim() || !commentingLine} style={{ padding: '0.45rem 0.85rem', fontSize: '0.8rem', flexShrink: 0 }}>
                              {commentSaving ? 'Guardando...' : 'Comentar'}
                            </button>
                          </div>
                        </div>
                      )}

                      {/* Code Sandbox Component */}
                      <CodeSandbox 
                        code={selectedFile.content || ''} 
                        language={getLanguage(getFileName(selectedFile.path))} 
                      />
                    </>
                  ) : (
                    <div className="empty-state" style={{ minHeight: '400px' }}>
                      <Terminal size={48} color="var(--on-surface-variant)" />
                      <p>Selecciona un archivo del explorador para ver su código.</p>
                    </div>
                  )}
                </div>
              </div>
            </>
          )}
        </div>

        {/* Modal: Crear Archivo */}
        {showUploadModal && (
          <div className="modal-overlay" onClick={() => setShowUploadModal(false)}>
            <div className="modal-content animate-in" onClick={(e) => e.stopPropagation()}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 700 }}>Agregar Archivo al Repositorio</h2>
                <button onClick={() => setShowUploadModal(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--on-surface-variant)' }}><X size={20} /></button>
              </div>
              <form onSubmit={handleCreateFile} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface-variant)', marginBottom: '0.5rem', fontWeight: 500 }}>Ruta del Archivo</label>
                  <input className="input-field" placeholder="Ej: src/main.tsx" value={newFilePath} onChange={(e) => setNewFilePath(e.target.value)} required />
                </div>
                <div>
                  <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface-variant)', marginBottom: '0.5rem', fontWeight: 500 }}>Contenido del Código</label>
                  <textarea
                    className="input-field"
                    placeholder="Pega o escribe el código fuente aquí..."
                    value={newFileContent}
                    onChange={(e) => setNewFileContent(e.target.value)}
                    rows={12}
                    style={{ resize: 'vertical', fontFamily: 'JetBrains Mono, monospace', fontSize: '0.85rem' }}
                  />
                </div>
                <button type="submit" className="btn-primary" disabled={uploadLoading}>
                  {uploadLoading ? 'Guardando...' : 'Crear Archivo'}
                </button>
              </form>
            </div>
          </div>
        )}
      </div>
    </>
  );
}

