                  {/* Results */}
                  {searchResults.length > 0 && (
                    <div style={{ border: '1px solid rgba(72,72,73,0.2)', borderRadius: '0.5rem', maxHeight: '180px', overflowY: 'auto', background: 'var(--surface-container)' }}>
