                  )}
                  {searchQuery.length >= 2 && searchResults.length === 0 && (
                    <p style={{ fontSize: '0.8rem', color: 'var(--on-surface-variant)', textAlign: 'center', padding: '0.5rem' }}>
                      No se encontraron usuarios.
                    </p>
                  )}
                </div>
              )}
            </>
          )}
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { X, Search, CheckCircle, Loader2, FolderGit2, Info } from 'lucide-react';
import GithubIcon from '@/components/GithubIcon';
import { supabase } from '@/lib/supabase';

interface GithubRepo {
  id: number;
  name: string;
  description: string | null;
  language: string | null;
  default_branch: string;
  pushed_at: string;
  owner: { login: string };
  private: boolean;
}

interface Props {
  userId: string;
  onClose: () => void;
  onSuccess: () => void;
}

export default function GithubImportModal({ userId, onClose, onSuccess }: Props) {
  const [step, setStep] = useState<1 | 2 | 3>(1); // 1: Search, 2: Select, 3: Importing
  const [username, setUsername] = useState('');
  const [token, setToken] = useState(''); // Optional PAT for private repos/rate limits
  const [repos, setRepos] = useState<GithubRepo[]>([]);
  const [selectedRepo, setSelectedRepo] = useState<GithubRepo | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [importProgress, setImportProgress] = useState({ current: 0, total: 0, currentFile: '' });

  // 1. Fetch repositories from GitHub
  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!username.trim() && !token.trim()) {
      setError('Debes proveer un usuario o un Token de Acceso Personal');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const headers: Record<string, string> = {};
      if (token.trim()) {
        headers['Authorization'] = `token ${token.trim()}`;
      }

      // Si tenemos token pero no usuario, buscamos los repositorios del usuario autenticado
      const endpoint = (token.trim() && !username.trim())
        ? 'https://api.github.com/user/repos?sort=updated&per_page=100'
        : `https://api.github.com/users/${username.trim()}/repos?sort=updated&per_page=100`;

      const res = await fetch(endpoint, { headers });

      if (!res.ok) {
        if (res.status === 404) throw new Error('Usuario no encontrado');
        if (res.status === 403) throw new Error('Límite de la API de GitHub superado. Usa un Token provisto.');
        if (res.status === 401) throw new Error('Token de GitHub inválido');
        throw new Error(`Error de GitHub: ${res.statusText}`);
      }

      const data: GithubRepo[] = await res.json();
      setRepos(data);
      setStep(2);
    } catch (err: any) {
      setError(err.message || 'Error al buscar repositorios');
    } finally {
      setLoading(false);
    }
  };

  // 2. Fetch the entire tree of the selected repo and import to Supabase
  const handleImport = async () => {
    if (!selectedRepo) return;
    setStep(3);
    setLoading(true);
    setError('');

    try {
      const headers: Record<string, string> = {
        'Accept': 'application/vnd.github.v3+json',
      };
      if (token.trim()) {
        headers['Authorization'] = `token ${token.trim()}`;
      }

      // Paso 1: Crear el repositorio en Supabase
      const { data: repoData, error: repoError } = await supabase
        .from('repositories')
        .insert({
          name: selectedRepo.name,
          description: selectedRepo.description || 'Importado desde GitHub',
          primary_language: selectedRepo.language || 'Desconocido',
          owner_id: userId,
        })
        .select()
        .single();

      if (repoError) throw new Error(`Ocurrió un error al crear el repositorio en Supabase: ${repoError.message}`);

      const newRepoId = repoData.id;

      // Paso 2: Obtener el árbol de archivos (recursivo) de GitHub
      setImportProgress({ current: 0, total: 0, currentFile: 'Obteniendo estructura...' });

      const treeUrl = `https://api.github.com/repos/${selectedRepo.owner.login}/${selectedRepo.name}/git/trees/${selectedRepo.default_branch}?recursive=1`;
      const treeRes = await fetch(treeUrl, { headers });

      if (!treeRes.ok) throw new Error('No se pudo obtener la estructura del repositorio desde GitHub');

      const treeData = await treeRes.json();

      // Filtrar solo archivos (blobs), omitir carpetas vacías (trees) y submodulos (commits)
      const files = treeData.tree.filter((node: any) => node.type === 'blob');

      setImportProgress({ current: 0, total: files.length, currentFile: 'Preparando descarga...' });

      // Definir límite de archivos para no sobrecargar el navegador de golpe (batch processing)
      const maxFiles = Math.min(files.length, 150); // Importar máximo 150 archivos para evitar límites

      // Paso 3: Descargar el contenido de los archivos y guardarlos
      let processed = 0;

      for (let i = 0; i < maxFiles; i++) {
        const fileNode = files[i];
        setImportProgress({ current: i, total: maxFiles, currentFile: fileNode.path });

        // Determinar cómo descargar:
        // Si el archivo es grande o es binario, lo saltamos por simplicidad (AIS Lab está pensado para código)
        // Obtenemos el contenido directamente con fetch rawusercontent o API contents

        let fileContent = '';
        const rawUrl = `https://raw.githubusercontent.com/${selectedRepo.owner.login}/${selectedRepo.name}/${selectedRepo.default_branch}/${fileNode.path}`;

        try {
          const contentRes = await fetch(rawUrl, { headers });
          if (contentRes.ok) {
            fileContent = await contentRes.text();

            // Insertar archivo en Supabase
            await supabase.from('repository_files').insert({
              repo_id: newRepoId,
              path: fileNode.path,
              content: fileContent,
            });
            processed++;
          }
        } catch (fileErr) {
          console.warn(`[GithubImport] Error al procesar ${fileNode.path}:`, fileErr);
          // Continuamos con el siguiente
        }
      }

      setImportProgress({ current: maxFiles, total: maxFiles, currentFile: `¡Completado! ${processed} archivos importados.` });

      setTimeout(() => {
        onSuccess();
      }, 1500);

    } catch (err: any) {
      setError(err.message || 'Error durante la importación');
      setStep(2); // Volver atrás si falla
    } finally {
      if (step !== 3) setLoading(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div 
        className="modal-content animate-in" 
        onClick={(e) => e.stopPropagation()} 
        style={{ maxWidth: '600px', width: '100%' }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <GithubIcon size={24} color="var(--primary)" />
            <h2 style={{ fontSize: '1.25rem', fontWeight: 700 }}>Importar de GitHub</h2>
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--on-surface-variant)' }}>
            <X size={20} />
          </button>
        </div>

        {error && (
          <div style={{ background: 'rgba(255,113,108,0.1)', color: 'var(--error)', padding: '0.75rem', borderRadius: '0.5rem', marginBottom: '1rem', fontSize: '0.875rem' }}>
            {error}
          </div>
        )}

        {/* STEP 1: Search configuration */}
        {step === 1 && (
          <form onSubmit={handleSearch} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            <p style={{ color: 'var(--on-surface-variant)', fontSize: '0.9rem', marginBottom: '0.5rem', lineHeight: 1.5 }}>
              Ingresa el nombre de usuario de GitHub para buscar repositorios públicos. Si necesitas importar un repositorio privado, debes proporcionar un Personal Access Token.
            </p>

            <div>
              <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                Usuario de GitHub <span style={{ color: 'var(--on-surface-variant)' }}>(Opcional si usas Token)</span>
              </label>
              <div style={{ position: 'relative' }}>
                <Search size={18} color="var(--on-surface-variant)" style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)' }} />
                <input 
                  className="input-field" 
                  placeholder="ej. torvalds" 
                  value={username} 
                  onChange={(e) => setUsername(e.target.value)} 
                  style={{ paddingLeft: '2.5rem' }} 
                />
              </div>
            </div>

            <div>
              <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                Token de Acceso Personal (PAT) <span style={{ color: 'var(--on-surface-variant)' }}>(Opcional)</span>
              </label>
              <input 
                type="password"
                className="input-field" 
                placeholder="ghp_****************************" 
                value={token} 
                onChange={(e) => setToken(e.target.value)} 
              />
              <p style={{ fontSize: '0.7rem', color: 'var(--on-surface-variant)', marginTop: '0.5rem' }}>
                Concédele permisos de <strong>"repo"</strong> en GitHub si deseas importar archivos privados.
              </p>
            </div>

            <button type="submit" className="btn-primary" disabled={loading} style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '0.5rem', marginTop: '0.5rem' }}>
              {loading ? <Loader2 size={18} className="spinner" style={{ border: 'none' }} /> : <Search size={18} />}
              {loading ? 'Buscando...' : 'Buscar Repositorios'}
            </button>
          </form>
        )}

        {/* STEP 2: Select Repository */}
        {step === 2 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <p style={{ color: 'var(--on-surface-variant)', fontSize: '0.9rem' }}>
                Se encontraron <strong>{repos.length}</strong> repositorios para <strong>{username || 'tu cuenta'}</strong>.
              </p>
              <button 
                onClick={() => setStep(1)} 
                style={{ background: 'none', border: 'none', color: 'var(--primary)', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 500 }}
              >
                Cambiar búsqueda
              </button>
            </div>

            <div style={{ border: '1px solid rgba(72,72,73,0.3)', borderRadius: '0.5rem', maxHeight: '300px', overflowY: 'auto', background: 'var(--surface-container)' }}>
              {repos.length === 0 ? (
                <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--on-surface-variant)' }}>No hay repositorios disponibles.</div>
              ) : (
                repos.map(repo => (
                  <div 
                    key={repo.id}
                    onClick={() => setSelectedRepo(repo)}
                    style={{ 
                      padding: '1rem', 
                      borderBottom: '1px solid rgba(72,72,73,0.2)',
                      cursor: 'pointer',
                      background: selectedRepo?.id === repo.id ? 'rgba(109,221,255,0.1)' : 'transparent',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '1rem',
                      transition: 'background 0.2s',
                    }}
                    onMouseEnter={(e) => {
                      if (selectedRepo?.id !== repo.id) e.currentTarget.style.background = 'rgba(255,255,255,0.03)';
                    }}
                    onMouseLeave={(e) => {
                      if (selectedRepo?.id !== repo.id) e.currentTarget.style.background = 'transparent';
                    }}
                  >
                    <FolderGit2 size={24} color={selectedRepo?.id === repo.id ? 'var(--primary)' : 'var(--on-surface-variant)'} />
                    <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <strong style={{ fontSize: '1rem' }}>{repo.name}</strong>
                        {repo.private && <span style={{ fontSize: '0.65rem', padding: '0.1rem 0.4rem', background: 'var(--surface-bright)', borderRadius: '1rem', border: '1px solid var(--outline)' }}>Privado</span>}
                      </div>
                      <p style={{ fontSize: '0.8rem', color: 'var(--on-surface-variant)', marginTop: '0.2rem', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', maxWidth: '350px' }}>
                        {repo.description || 'Sin descripción'}
                      </p>
                    </div>
                    {selectedRepo?.id === repo.id && <CheckCircle size={20} color="var(--primary)" />}
                  </div>
                ))
              )}
            </div>

            <div style={{ background: 'rgba(109,221,255,0.05)', padding: '1rem', borderRadius: '0.5rem', display: 'flex', alignItems: 'flex-start', gap: '0.75rem' }}>
              <Info size={18} color="var(--primary)" style={{ flexShrink: 0, marginTop: '2px' }} />
              <p style={{ fontSize: '0.8rem', color: 'var(--on-surface-variant)', lineHeight: 1.5 }}>
                Al importar, se crearán copias Snapshot del código actual de la rama principal (<strong>{selectedRepo?.default_branch || 'main'}</strong>) localmente en AIS Lab para acelerar la vista del código.
              </p>
            </div>

            <button 
              onClick={handleImport} 
              className="btn-primary" 
              disabled={!selectedRepo || loading}
              style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', marginTop: '0.5rem' }}
            >
              {loading ? 'Preparando...' : `Importar ${selectedRepo ? `'${selectedRepo.name}'` : ''}`}
            </button>
          </div>
        )}

        {/* STEP 3: Progress Indicator */}
        {step === 3 && (
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1.5rem', padding: '2rem 1rem' }}>
            <div style={{ position: 'relative', width: '80px', height: '80px' }}>
              <svg style={{ width: '100%', height: '100%', transform: 'rotate(-90deg)' }}>
                <circle cx="40" cy="40" r="36" fill="transparent" stroke="var(--surface-bright)" strokeWidth="6" />
                <circle 
                  cx="40" cy="40" r="36" 
                  fill="transparent" 
                  stroke="var(--primary)" 
                  strokeWidth="6"
                  strokeDasharray="226"
                  strokeDashoffset={226 - (226 * (importProgress.current / Math.max(importProgress.total, 1)))}
                  style={{ transition: 'stroke-dashoffset 0.3s ease' }}
                />
              </svg>
              <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem', fontWeight: 700 }}>
                {importProgress.total > 0 ? Math.round((importProgress.current / importProgress.total) * 100) : 0}%
              </div>
            </div>

            <div style={{ textAlign: 'center' }}>
              <h3 style={{ fontSize: '1.1rem', fontWeight: 600, marginBottom: '0.5rem' }}>Clonando repositorio...</h3>
              <p style={{ fontSize: '0.85rem', color: 'var(--on-surface-variant)', fontFamily: 'monospace', maxWidth: '400px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                {importProgress.currentFile}
              </p>
              <p style={{ fontSize: '0.85rem', color: 'var(--primary)', marginTop: '1rem', fontWeight: 500 }}>
                {importProgress.current} / {importProgress.total} archivos procesados
              </p>
            </div>

            <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', textAlign: 'center', marginTop: '1rem' }}>
              Por favor, no cierres esta ventana hasta que el proceso termine.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { supabase } from '@/lib/supabase';
import { Award, CheckCircle, XCircle, Edit3, Save, Trash2, ChevronDown, ChevronUp } from 'lucide-react';

interface Grade {
  id: string;
  teacher_id: string;
  student_id: string;
  repo_id: string;
  score: number;
  feedback: string | null;
  created_at: string;
  updated_at: string;
  teacher_name?: string;
}

interface Props {
  repoId: string;
  userId: string;
  userRole: string;
  repoOwnerId: string;
}

export default function GradingPanel({ repoId, userId, userRole, repoOwnerId }: Props) {
  const [grades, setGrades] = useState<Grade[]>([]);
  const [isExpanded, setIsExpanded] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [score, setScore] = useState<number>(0);
  const [feedback, setFeedback] = useState('');
  const [loading, setLoading] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  const isTeacher = userRole === 'docente' || userRole === 'superadministrador';
  const isOwner = userId === repoOwnerId;

  useEffect(() => {
    loadGrades();
  }, [repoId]);

  const loadGrades = async () => {
    const { data, error } = await supabase
      .from('grades')
      .select('*')
      .eq('repo_id', repoId)
      .order('created_at', { ascending: false });

    if (error) { console.error('[Grades] Load error:', error); return; }

    // Fetch teacher names
    if (data && data.length > 0) {
      const teacherIds = [...new Set(data.map(g => g.teacher_id).filter(Boolean))];
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, full_name')
        .in('id', teacherIds);

      const nameMap: Record<string, string> = {};
      profiles?.forEach(p => { nameMap[p.id] = p.full_name || 'Docente'; });

      data.forEach(g => { g.teacher_name = nameMap[g.teacher_id] || 'Docente'; });
    }

    setGrades(data || []);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (score < 0 || score > 100) return;
    setLoading(true);

    try {
      if (editingId) {
        // Update existing grade
        const { error } = await supabase
          .from('grades')
          .update({ score, feedback: feedback || null, updated_at: new Date().toISOString() })
          .eq('id', editingId);
        if (error) throw error;
      } else {
        // Insert new grade
        const { error } = await supabase
          .from('grades')
          .insert({
            teacher_id: userId,
            student_id: repoOwnerId,
            repo_id: repoId,
            score,
            feedback: feedback || null,
          });
        if (error) throw error;
      }

      setShowForm(false);
      setEditingId(null);
      setScore(0);
      setFeedback('');
      loadGrades();
    } catch (err: any) {
      console.error('[Grades] Save error:', err);
      alert(err.message || 'Error al guardar la calificación');
    } finally {
      setLoading(false);
    }
  };

  const deleteGrade = async (id: string) => {
    if (!confirm('¿Eliminar esta calificación?')) return;
    await supabase.from('grades').delete().eq('id', id);
    loadGrades();
  };

  const startEdit = (grade: Grade) => {
    setEditingId(grade.id);
    setScore(grade.score);
    setFeedback(grade.feedback || '');
    setShowForm(true);
  };

  const getScoreColor = (s: number) => {
    if (s >= 80) return 'var(--tertiary)';
    if (s >= 60) return 'var(--primary)';
    if (s >= 40) return '#ffb74d';
    return 'var(--error)';
  };

  const getScoreLabel = (s: number) => {
    if (s >= 90) return 'Excelente';
    if (s >= 80) return 'Muy Bueno';
    if (s >= 70) return 'Bueno';
    if (s >= 60) return 'Aprobado';
    return 'Reprobado';
  };

  // Check if this teacher already graded this repo
  const alreadyGraded = grades.some(g => g.teacher_id === userId);

  return (
    <div style={{
      background: 'var(--surface-container)',
      border: '1px solid rgba(72,72,73,0.15)',
      borderRadius: '0.75rem',
      overflow: 'hidden',
    }}>
      {/* Header */}
      <button
        onClick={() => setIsExpanded(!isExpanded)}
        style={{
          width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          padding: '1rem 1.25rem', background: 'none', border: 'none', cursor: 'pointer',
          color: 'var(--on-surface)', fontFamily: 'Inter',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <Award size={20} color="var(--secondary)" />
          <span style={{ fontWeight: 700, fontSize: '0.95rem' }}>Evaluación del Repositorio</span>
          {grades.length > 0 && (
            <span className="badge badge-purple" style={{ marginLeft: '0.5rem' }}>
              {grades.length} {grades.length === 1 ? 'nota' : 'notas'}
            </span>
          )}
        </div>
        {isExpanded ? <ChevronUp size={18} color="var(--on-surface-variant)" /> : <ChevronDown size={18} color="var(--on-surface-variant)" />}
      </button>

      {isExpanded && (
        <div style={{ padding: '0 1.25rem 1.25rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
          {/* Existing grades */}
          {grades.length > 0 ? (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              {grades.map(grade => (
                <div key={grade.id} style={{
                  background: 'var(--surface-container-high)',
                  border: '1px solid rgba(72,72,73,0.1)',
                  borderRadius: '0.75rem',
                  padding: '1.25rem',
                  display: 'flex',
                  gap: '1.25rem',
                  alignItems: 'flex-start',
                }}>
                  {/* Score circle */}
                  <div style={{
                    width: '64px', height: '64px',
                    borderRadius: '50%',
                    border: `3px solid ${getScoreColor(grade.score)}`,
                    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                    flexShrink: 0,
                    background: `${getScoreColor(grade.score)}11`,
                  }}>
                    <span style={{ fontSize: '1.25rem', fontWeight: 800, color: getScoreColor(grade.score), lineHeight: 1 }}>
                      {grade.score}
                    </span>
                    <span style={{ fontSize: '0.55rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>/100</span>
                  </div>

                  {/* Details */}
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
                      {grade.score >= 60
                        ? <CheckCircle size={16} color="var(--tertiary)" />
                        : <XCircle size={16} color="var(--error)" />
                      }
                      <span style={{
                        fontSize: '0.85rem', fontWeight: 700,
                        color: grade.score >= 60 ? 'var(--tertiary)' : 'var(--error)',
                      }}>
                        {getScoreLabel(grade.score)}
                      </span>
                    </div>
                    {grade.feedback && (
                      <p style={{ fontSize: '0.85rem', color: 'var(--on-surface-variant)', lineHeight: 1.6, marginBottom: '0.5rem' }}>
                        {grade.feedback}
                      </p>
                    )}
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: '0.5rem' }}>
                      <span style={{ fontSize: '0.7rem', color: 'var(--outline)' }}>
                        Evaluado por <strong style={{ color: 'var(--secondary)' }}>{grade.teacher_name}</strong>
                        {' · '}
                        {new Date(grade.created_at).toLocaleDateString('es-VE', { day: 'numeric', month: 'short', year: 'numeric' })}
                      </span>
                      {/* Edit/Delete buttons for the teacher who gave the grade or superadmin */}
                      {(grade.teacher_id === userId || userRole === 'superadministrador') && (
                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                          <button
                            onClick={() => startEdit(grade)}
                            style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--primary)', padding: '0.25rem' }}
                            title="Editar calificación"
                          >
                            <Edit3 size={14} />
                          </button>
                          {userRole === 'superadministrador' && (
                            <button
                              onClick={() => deleteGrade(grade.id)}
                              style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--error)', padding: '0.25rem' }}
                              title="Eliminar calificación"
                            >
                              <Trash2 size={14} />
                            </button>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div style={{ textAlign: 'center', padding: '1.5rem 1rem', color: 'var(--on-surface-variant)', fontSize: '0.85rem' }}>
              Este repositorio aún no ha sido evaluado.
            </div>
          )}

          {/* Grade form — only for teachers who haven't graded yet, or when editing */}
          {isTeacher && !isOwner && (!alreadyGraded || editingId) && (
            <>
              {!showForm ? (
                <button
                  className="btn-primary"
                  onClick={() => setShowForm(true)}
                  style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                >
                  <Award size={16} /> Asignar Calificación
                </button>
              ) : (
                <form onSubmit={handleSubmit} style={{
                  background: 'var(--surface-container-high)',
                  border: '1px solid rgba(193,128,255,0.2)',
                  borderRadius: '0.75rem',
                  padding: '1.25rem',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: '1rem',
                }}>
                  <h4 style={{ fontSize: '0.9rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Award size={16} color="var(--secondary)" />
                    {editingId ? 'Editar Calificación' : 'Nueva Calificación'}
                  </h4>

                  {/* Score slider + number input */}
                  <div>
                    <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                      Puntuación: <strong style={{ color: getScoreColor(score), fontSize: '1.1rem' }}>{score}/100</strong>
                      <span style={{ marginLeft: '0.5rem', fontSize: '0.75rem', color: score >= 60 ? 'var(--tertiary)' : 'var(--error)' }}>
                        ({getScoreLabel(score)})
                      </span>
                    </label>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                      <input
                        type="range"
                        min="0"
                        max="100"
                        value={score}
                        onChange={(e) => setScore(Number(e.target.value))}
                        style={{
                          flex: 1,
                          accentColor: getScoreColor(score),
                          height: '6px',
                        }}
                      />
                      <input
                        type="number"
                        min="0"
                        max="100"
                        value={score}
                        onChange={(e) => setScore(Math.min(100, Math.max(0, Number(e.target.value))))}
                        className="input-field"
                        style={{ width: '70px', textAlign: 'center', padding: '0.5rem' }}
                      />
                    </div>
                    {/* Visual bar */}
                    <div style={{ marginTop: '0.5rem', height: '4px', borderRadius: '2px', background: 'var(--surface-bright)', overflow: 'hidden' }}>
                      <div style={{
                        height: '100%',
                        width: `${score}%`,
                        background: `linear-gradient(90deg, var(--error), #ffb74d, var(--primary), var(--tertiary))`,
                        borderRadius: '2px',
                        transition: 'width 0.2s ease',
                      }} />
                    </div>
                  </div>

                  <div>
                    <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                      Feedback / Observaciones <span style={{ color: 'var(--on-surface-variant)' }}>(Opcional)</span>
                    </label>
                    <textarea
                      className="input-field"
                      value={feedback}
                      onChange={(e) => setFeedback(e.target.value)}
                      placeholder="Escribe tu retroalimentación para el estudiante..."
                      rows={3}
                      style={{ resize: 'vertical' }}
                    />
                  </div>

                  <div style={{ display: 'flex', gap: '0.75rem' }}>
                    <button
                      type="button"
                      className="btn-ghost"
                      onClick={() => { setShowForm(false); setEditingId(null); setScore(0); setFeedback(''); }}
                      style={{ flex: 1 }}
                    >
                      Cancelar
                    </button>
                    <button
                      type="submit"
                      className="btn-primary"
                      disabled={loading}
                      style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                    >
                      <Save size={16} /> {loading ? 'Guardando...' : editingId ? 'Actualizar' : 'Guardar Calificación'}
                    </button>
                  </div>
                </form>
              )}
            </>
          )}

          {/* Student view: if the current user is the owner, show a simple message */}
          {isOwner && grades.length === 0 && (
            <p style={{ fontSize: '0.8rem', color: 'var(--on-surface-variant)', textAlign: 'center', fontStyle: 'italic' }}>
              Tu docente aún no ha evaluado este repositorio.
            </p>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useRef, useCallback } from 'react';
import JSZip from 'jszip';
import { X, UploadCloud, FileArchive, CheckCircle2, AlertTriangle, File } from 'lucide-react';
import { supabase } from '@/lib/supabase';

interface Props {
  userId: string;
  onClose: () => void;
  onSuccess: () => void;
}

// Extensions that are considered "code/text" and safe to store as text in the DB
const TEXT_EXTENSIONS = new Set([
  '.ts', '.tsx', '.js', '.jsx', '.json', '.css', '.scss', '.less', '.sass',
  '.html', '.htm', '.xml', '.svg', '.md', '.mdx', '.txt', '.yaml', '.yml',
  '.toml', '.ini', '.cfg', '.conf', '.env', '.env.local', '.env.example',
  '.py', '.pyw', '.pyi', '.java', '.kt', '.kts', '.scala', '.groovy',
  '.c', '.h', '.cpp', '.hpp', '.cc', '.cxx', '.cs', '.go', '.rs', '.rb',
  '.php', '.pl', '.pm', '.lua', '.r', '.R', '.swift', '.m', '.mm',
  '.sh', '.bash', '.zsh', '.fish', '.bat', '.cmd', '.ps1',
  '.sql', '.graphql', '.gql', '.prisma', '.proto',
  '.dockerfile', '.dockerignore', '.gitignore', '.gitattributes',
  '.editorconfig', '.prettierrc', '.eslintrc', '.babelrc',
  '.vue', '.svelte', '.astro',
  '.lock', '.map',
]);

// Directories to always skip
const IGNORED_DIRS = new Set([
  'node_modules', '.git', '__pycache__', '.vscode', '.idea',
  'dist', 'build', '.next', '.nuxt', 'vendor', '.cache',
  'coverage', '.nyc_output', 'target', 'bin', 'obj',
]);

function isTextFile(path: string): boolean {
  // Check if the file name itself is a known config file without extension
  const basename = path.split('/').pop() || '';
  if (['Makefile', 'Dockerfile', 'Procfile', 'Gemfile', 'Rakefile', '.gitignore', '.dockerignore', '.editorconfig'].includes(basename)) {
    return true;
  }
  const dotIndex = basename.lastIndexOf('.');
  if (dotIndex === -1) return false; // No extension, skip unless it's a known file
  const ext = basename.substring(dotIndex).toLowerCase();
  return TEXT_EXTENSIONS.has(ext);
}

function isIgnoredPath(path: string): boolean {
  const parts = path.split('/');
  return parts.some(part => IGNORED_DIRS.has(part));
}

export default function LocalUploadModal({ userId, onClose, onSuccess }: Props) {
  const [step, setStep] = useState<1 | 2 | 3>(1); // 1=select, 2=preview, 3=uploading
  const [file, setFile] = useState<File | null>(null);
  const [repoName, setRepoName] = useState('');
  const [repoDesc, setRepoDesc] = useState('');
  const [extractedFiles, setExtractedFiles] = useState<{ path: string; content: string }[]>([]);
  const [skippedCount, setSkippedCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [progress, setProgress] = useState({ current: 0, total: 0, currentFile: '' });
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handle file selection (click or drop)
  const processFile = useCallback(async (selectedFile: File) => {
    if (!selectedFile.name.toLowerCase().endsWith('.zip')) {
      setError('Solo se admiten archivos en formato .zip');
      return;
    }
    if (selectedFile.size > 100 * 1024 * 1024) { // 100MB limit
      setError('El archivo excede el límite de 100MB.');
      return;
    }

    setFile(selectedFile);
    setError('');
    setLoading(true);

    try {
      const zip = new JSZip();
      const contents = await zip.loadAsync(selectedFile);
      const files: { path: string; content: string }[] = [];
      let skipped = 0;

      // Find common root: if all files share a single top-level folder, strip it
      const allPaths = Object.keys(contents.files).filter(p => !contents.files[p].dir);
      let commonPrefix = '';
      if (allPaths.length > 0) {
        const firstSlash = allPaths[0].indexOf('/');
        if (firstSlash > 0) {
          const candidate = allPaths[0].substring(0, firstSlash + 1);
          if (allPaths.every(p => p.startsWith(candidate))) {
            commonPrefix = candidate;
          }
        }
      }

      for (const [relativePath, zipEntry] of Object.entries(contents.files)) {
        if (zipEntry.dir) continue; // Skip directories

        // Strip common prefix
        const cleanPath = commonPrefix ? relativePath.replace(commonPrefix, '') : relativePath;
        if (!cleanPath) continue;

        if (isIgnoredPath(cleanPath)) { skipped++; continue; }
        if (!isTextFile(cleanPath)) { skipped++; continue; }

        try {
          const text = await zipEntry.async('string');
          // Skip files that look binary (contain null bytes)
          if (text.includes('\0')) { skipped++; continue; }
          // Skip very large individual files (>500KB)
          if (text.length > 500 * 1024) { skipped++; continue; }

          files.push({ path: cleanPath, content: text });
        } catch {
          skipped++;
        }
      }

      setExtractedFiles(files);
      setSkippedCount(skipped);

      // Suggest repo name from ZIP filename
      const suggestedName = selectedFile.name.replace(/\.zip$/i, '').replace(/[-_]/g, ' ');
      setRepoName(suggestedName);
      setStep(2);
    } catch (err) {
      console.error('[LocalUpload] Error reading zip:', err);
      setError('No se pudo leer el archivo ZIP. Verifica que no esté corrupto.');
    } finally {
      setLoading(false);
    }
  }, []);

  // Drag & Drop handlers
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    const droppedFile = e.dataTransfer.files[0];
    if (droppedFile) processFile(droppedFile);
  }, [processFile]);

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) processFile(selectedFile);
  }, [processFile]);

  // Upload to Supabase
  const handleUpload = async () => {
    if (extractedFiles.length === 0 || !repoName.trim()) return;
    setStep(3);
    setLoading(true);
    setError('');

    try {
      // Create repo
      const { data: repoData, error: repoError } = await supabase
        .from('repositories')
        .insert({
          name: repoName.trim(),
          description: repoDesc.trim() || `Subido desde archivo local (${file?.name})`,
          primary_language: detectLanguage(extractedFiles),
          owner_id: userId,
        })
        .select()
        .single();

      if (repoError) throw new Error(`Error creando repositorio: ${repoError.message}`);
      const newRepoId = repoData.id;

      // Insert files in batches of 20
      const batchSize = 20;
      const total = extractedFiles.length;

      for (let i = 0; i < total; i += batchSize) {
        const batch = extractedFiles.slice(i, i + batchSize);
        setProgress({
          current: Math.min(i + batchSize, total),
          total,
          currentFile: batch[batch.length - 1]?.path || '',
        });

        const rows = batch.map(f => ({
          repo_id: newRepoId,
          path: f.path,
          content: f.content,
        }));

        const { error: insertError } = await supabase.from('repository_files').insert(rows);
        if (insertError) {
          console.warn('[LocalUpload] Batch insert error:', insertError.message);
        }
      }

      setProgress({ current: total, total, currentFile: '¡Completado!' });
      setTimeout(() => onSuccess(), 1200);
    } catch (err: any) {
      setError(err.message || 'Error durante la subida');
      setStep(2);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div
        className="modal-content animate-in"
        onClick={(e) => e.stopPropagation()}
        style={{ maxWidth: '600px', width: '100%' }}
      >
        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <FileArchive size={24} color="var(--secondary)" />
            <h2 style={{ fontSize: '1.25rem', fontWeight: 700 }}>Subir Archivo Comprimido</h2>
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--on-surface-variant)' }}>
            <X size={20} />
          </button>
        </div>

        {error && (
          <div style={{ background: 'rgba(255,113,108,0.1)', color: 'var(--error)', padding: '0.75rem', borderRadius: '0.5rem', marginBottom: '1rem', fontSize: '0.875rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <AlertTriangle size={16} /> {error}
          </div>
        )}

        {/* STEP 1: Drag & Drop or Click to select */}
        {step === 1 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            <p style={{ color: 'var(--on-surface-variant)', fontSize: '0.9rem', lineHeight: 1.5 }}>
              Arrastra tu archivo <strong>.zip</strong> aquí o haz clic para seleccionarlo. El sistema extraerá automáticamente los archivos de código fuente y los subirá al repositorio.
            </p>

            <div
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              onDrop={handleDrop}
              onClick={() => fileInputRef.current?.click()}
              style={{
                border: `2px dashed ${isDragging ? 'var(--primary)' : 'var(--outline-variant)'}`,
                borderRadius: '1rem',
                padding: '3rem 2rem',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '1rem',
                cursor: 'pointer',
                background: isDragging ? 'rgba(109,221,255,0.06)' : 'rgba(26,25,27,0.3)',
                transition: 'all 0.25s ease',
              }}
            >
              <UploadCloud size={48} color={isDragging ? 'var(--primary)' : 'var(--on-surface-variant)'} strokeWidth={1.5} />
              <div style={{ textAlign: 'center' }}>
                <p style={{ fontWeight: 600, fontSize: '1rem', marginBottom: '0.25rem' }}>
                  {isDragging ? '¡Suelta el archivo aquí!' : 'Arrastra tu archivo .zip'}
                </p>
                <p style={{ color: 'var(--on-surface-variant)', fontSize: '0.8rem' }}>
                  o haz clic para seleccionar desde tu computadora
                </p>
              </div>
              <span style={{ fontSize: '0.7rem', color: 'var(--outline)', marginTop: '0.5rem' }}>
                Máximo 100 MB • Solo formato .zip
              </span>
            </div>

            <input
              ref={fileInputRef}
              type="file"
              accept=".zip"
              onChange={handleFileInput}
              style={{ display: 'none' }}
            />

            {loading && (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.75rem', padding: '1rem' }}>
                <div className="spinner" />
                <span style={{ fontSize: '0.9rem', color: 'var(--on-surface-variant)' }}>Leyendo archivo ZIP...</span>
              </div>
            )}
          </div>
        )}

        {/* STEP 2: Preview extracted files + config */}
        {step === 2 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {/* Stats */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem' }}>
              <div style={{ background: 'rgba(109,221,255,0.06)', padding: '1rem', borderRadius: '0.75rem', textAlign: 'center' }}>
                <p style={{ fontSize: '1.5rem', fontWeight: 700, color: 'var(--primary)' }}>{extractedFiles.length}</p>
                <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>Archivos de código</p>
              </div>
              <div style={{ background: 'rgba(193,128,255,0.06)', padding: '1rem', borderRadius: '0.75rem', textAlign: 'center' }}>
                <p style={{ fontSize: '1.5rem', fontWeight: 700, color: 'var(--secondary)' }}>{skippedCount}</p>
                <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', fontWeight: 500 }}>Archivos omitidos</p>
              </div>
            </div>

            {/* Repo config */}
            <div>
              <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                Nombre del Repositorio
              </label>
              <input
                className="input-field"
                value={repoName}
                onChange={(e) => setRepoName(e.target.value)}
                placeholder="Nombre de tu proyecto"
                required
              />
            </div>
            <div>
              <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                Descripción <span style={{ color: 'var(--on-surface-variant)' }}>(Opcional)</span>
              </label>
              <input
                className="input-field"
                value={repoDesc}
                onChange={(e) => setRepoDesc(e.target.value)}
                placeholder="¿De qué trata este proyecto?"
              />
            </div>

            {/* File list preview */}
            <div>
              <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--on-surface)', marginBottom: '0.5rem', fontWeight: 500 }}>
                Archivos a subir ({extractedFiles.length})
              </label>
              <div style={{
                border: '1px solid rgba(72,72,73,0.3)',
                borderRadius: '0.5rem',
                maxHeight: '180px',
                overflowY: 'auto',
                background: 'var(--surface-container)',
              }}>
                {extractedFiles.slice(0, 100).map((f, i) => (
                  <div key={i} style={{
                    padding: '0.5rem 0.75rem',
                    borderBottom: '1px solid rgba(72,72,73,0.15)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '0.5rem',
                    fontSize: '0.8rem',
                    fontFamily: 'JetBrains Mono, monospace',
                    color: 'var(--on-surface-variant)',
                  }}>
                    <File size={14} color="var(--primary)" style={{ flexShrink: 0 }} />
                    <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{f.path}</span>
                  </div>
                ))}
                {extractedFiles.length > 100 && (
                  <div style={{ padding: '0.5rem 0.75rem', fontSize: '0.75rem', color: 'var(--outline)', textAlign: 'center' }}>
                    ... y {extractedFiles.length - 100} archivos más
                  </div>
                )}
              </div>
            </div>

            {/* Actions */}
            <div style={{ display: 'flex', gap: '0.75rem', marginTop: '0.5rem' }}>
              <button
                className="btn-ghost"
                onClick={() => { setStep(1); setFile(null); setExtractedFiles([]); }}
                style={{ flex: 1 }}
              >
                Cambiar archivo
              </button>
              <button
                className="btn-primary"
                onClick={handleUpload}
                disabled={!repoName.trim() || extractedFiles.length === 0}
                style={{ flex: 1 }}
              >
                Subir {extractedFiles.length} archivos
              </button>
            </div>
          </div>
        )}

        {/* STEP 3: Progress */}
        {step === 3 && (
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1.5rem', padding: '2rem 1rem' }}>
            <div style={{ position: 'relative', width: '80px', height: '80px' }}>
              <svg style={{ width: '100%', height: '100%', transform: 'rotate(-90deg)' }}>
                <circle cx="40" cy="40" r="36" fill="transparent" stroke="var(--surface-bright)" strokeWidth="6" />
                <circle
                  cx="40" cy="40" r="36"
                  fill="transparent"
                  stroke="var(--secondary)"
                  strokeWidth="6"
                  strokeDasharray="226"
                  strokeDashoffset={226 - (226 * (progress.current / Math.max(progress.total, 1)))}
                  style={{ transition: 'stroke-dashoffset 0.3s ease' }}
                />
              </svg>
              <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem', fontWeight: 700 }}>
                {progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0}%
              </div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <h3 style={{ fontSize: '1.1rem', fontWeight: 600, marginBottom: '0.5rem' }}>
                {progress.current === progress.total ? '¡Subida completa!' : 'Subiendo archivos...'}
              </h3>
              <p style={{ fontSize: '0.85rem', color: 'var(--on-surface-variant)', fontFamily: 'monospace', maxWidth: '400px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                {progress.currentFile}
              </p>
              <p style={{ fontSize: '0.85rem', color: 'var(--secondary)', marginTop: '1rem', fontWeight: 500 }}>
                {progress.current} / {progress.total} archivos procesados
              </p>
            </div>
            {progress.current === progress.total && (
              <CheckCircle2 size={32} color="var(--tertiary)" style={{ animation: 'fadeIn 0.5s ease' }} />
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/** Detect the primary language based on file extensions */
function detectLanguage(files: { path: string }[]): string {
  const counts: Record<string, number> = {};
  const langMap: Record<string, string> = {
    '.ts': 'TypeScript', '.tsx': 'TypeScript',
    '.js': 'JavaScript', '.jsx': 'JavaScript',
    '.py': 'Python', '.pyw': 'Python',
    '.java': 'Java', '.kt': 'Kotlin',
    '.c': 'C', '.cpp': 'C++', '.cs': 'C#',
    '.go': 'Go', '.rs': 'Rust', '.rb': 'Ruby',
    '.php': 'PHP', '.swift': 'Swift',
    '.html': 'HTML', '.css': 'CSS',
    '.vue': 'Vue', '.svelte': 'Svelte',
  };

  for (const f of files) {
    const ext = f.path.substring(f.path.lastIndexOf('.')).toLowerCase();
    const lang = langMap[ext];
    if (lang) counts[lang] = (counts[lang] || 0) + 1;
  }

  let best = 'Otro';
  let max = 0;
  for (const [lang, count] of Object.entries(counts)) {
    if (count > max) { max = count; best = lang; }
  }
  return best;
}

