'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { Bell, MessageSquare, Award, UserPlus, MessageCircle, Info, Check, Trash2, CheckCheck } from 'lucide-react';

interface Notification {
  id: string;
  user_id: string;
  type: 'comment' | 'grade' | 'invite' | 'forum_reply' | 'system';
  title: string;
  content: string | null;
  link: string | null;
  read: boolean;
  created_at: string;
}

const typeConfig: Record<string, { icon: React.ElementType; color: string; bg: string }> = {
  comment: { icon: MessageSquare, color: 'var(--primary)', bg: 'rgba(109,221,255,0.12)' },
  grade: { icon: Award, color: 'var(--secondary)', bg: 'rgba(193,128,255,0.12)' },
  invite: { icon: UserPlus, color: 'var(--tertiary)', bg: 'rgba(155,255,206,0.12)' },
  forum_reply: { icon: MessageCircle, color: '#ffb74d', bg: 'rgba(255,183,77,0.12)' },
  system: { icon: Info, color: 'var(--on-surface-variant)', bg: 'rgba(173,170,171,0.12)' },
};

interface Props {
  userId: string;
}

export default function NotificationBell({ userId }: Props) {
  const router = useRouter();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const panelRef = useRef<HTMLDivElement>(null);

  const loadNotifications = useCallback(async () => {
    const { data } = await supabase
      .from('notifications')
      .select('*')
      .eq('user_id', userId)
      .order('created_at', { ascending: false })
      .limit(30);

    const notifs = data || [];
    setNotifications(notifs);
    setUnreadCount(notifs.filter(n => !n.read).length);
  }, [userId]);

  // Initial load
  useEffect(() => {
    loadNotifications();
  }, [loadNotifications]);

  // Real-time subscription
  useEffect(() => {
    const channel = supabase
      .channel('notifications-realtime')
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${userId}` },
        (payload) => {
          const newNotif = payload.new as Notification;
          setNotifications(prev => [newNotif, ...prev].slice(0, 30));
          setUnreadCount(prev => prev + 1);
        }
      )
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, [userId]);

  // Close on click outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (isOpen && panelRef.current && !panelRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const markAsRead = async (id: string) => {
    await supabase.from('notifications').update({ read: true }).eq('id', id);
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
    setUnreadCount(prev => Math.max(0, prev - 1));
  };

  const markAllAsRead = async () => {
    await supabase.from('notifications').update({ read: true }).eq('user_id', userId).eq('read', false);
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
    setUnreadCount(0);
  };

  const deleteNotification = async (id: string, wasUnread: boolean) => {
    await supabase.from('notifications').delete().eq('id', id);
    setNotifications(prev => prev.filter(n => n.id !== id));
    if (wasUnread) setUnreadCount(prev => Math.max(0, prev - 1));
  };

  const handleClick = (notif: Notification) => {
    if (!notif.read) markAsRead(notif.id);
    if (notif.link) {
      router.push(notif.link);
      setIsOpen(false);
    }
  };

  const timeAgo = (dateStr: string) => {
    const diff = Date.now() - new Date(dateStr).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'ahora';
    if (mins < 60) return `${mins}m`;
    const hours = Math.floor(mins / 60);
    if (hours < 24) return `${hours}h`;
    const days = Math.floor(hours / 24);
    return `${days}d`;
  };

  return (
    <div ref={panelRef} style={{ position: 'relative' }}>
      {/* Bell button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        style={{
          background: 'none', border: 'none', cursor: 'pointer',
          color: 'var(--on-surface-variant)', padding: '0.5rem',
          borderRadius: '0.5rem', display: 'flex', alignItems: 'center',
          justifyContent: 'center', position: 'relative',
          transition: 'all 0.2s ease',
        }}
        onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(109,221,255,0.1)'; e.currentTarget.style.color = 'var(--primary)'; }}
        onMouseLeave={(e) => { e.currentTarget.style.background = 'none'; e.currentTarget.style.color = 'var(--on-surface-variant)'; }}
        aria-label="Notificaciones"
      >
        <Bell size={20} />
        {unreadCount > 0 && (
          <span style={{
            position: 'absolute', top: '2px', right: '2px',
            width: unreadCount > 9 ? '20px' : '16px', height: '16px',
            borderRadius: '9999px',
            background: 'var(--error)',
            color: '#fff',
            fontSize: '0.6rem',
            fontWeight: 800,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            border: '2px solid var(--surface-container-low)',
            animation: 'fadeIn 0.3s ease',
          }}>
            {unreadCount > 9 ? '9+' : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown Panel */}
      {isOpen && (
        <div style={{
          position: 'absolute',
          top: '100%',
          right: 0,
          marginTop: '0.5rem',
          width: '380px',
          maxHeight: '480px',
          background: 'var(--surface-container-high)',
          border: '1px solid rgba(72,72,73,0.2)',
          borderRadius: '0.75rem',
          boxShadow: '0 12px 40px rgba(0,0,0,0.5)',
          overflow: 'hidden',
          zIndex: 200,
          animation: 'fadeIn 0.2s ease',
        }}>
          {/* Header */}
          <div style={{
            padding: '1rem 1.25rem',
            borderBottom: '1px solid rgba(72,72,73,0.15)',
            display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <h3 style={{ fontSize: '0.95rem', fontWeight: 700, margin: 0 }}>Notificaciones</h3>
              {unreadCount > 0 && (
                <span className="badge badge-cyan">{unreadCount} nuevas</span>
              )}
            </div>
            {unreadCount > 0 && (
              <button
                onClick={markAllAsRead}
                style={{
                  background: 'none', border: 'none', cursor: 'pointer',
                  color: 'var(--primary)', fontSize: '0.75rem', fontWeight: 600,
                  fontFamily: 'Inter', display: 'flex', alignItems: 'center', gap: '0.3rem',
                }}
              >
                <CheckCheck size={14} /> Leer todas
              </button>
            )}
          </div>

          {/* Notification list */}
          <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
            {notifications.length === 0 ? (
              <div style={{ padding: '3rem 2rem', textAlign: 'center', color: 'var(--on-surface-variant)' }}>
                <Bell size={32} strokeWidth={1} style={{ opacity: 0.4, marginBottom: '0.75rem' }} />
                <p style={{ fontSize: '0.85rem' }}>Sin notificaciones</p>
              </div>
            ) : (
              notifications.map(notif => {
                const config = typeConfig[notif.type] || typeConfig.system;
                const Icon = config.icon;
                return (
                  <div
                    key={notif.id}
                    onClick={() => handleClick(notif)}
                    style={{
                      padding: '0.875rem 1.25rem',
                      borderBottom: '1px solid rgba(72,72,73,0.1)',
                      display: 'flex', gap: '0.75rem', alignItems: 'flex-start',
                      cursor: notif.link ? 'pointer' : 'default',
                      background: notif.read ? 'transparent' : 'rgba(109,221,255,0.03)',
                      transition: 'background 0.15s',
                    }}
                    onMouseEnter={(e) => { e.currentTarget.style.background = 'rgba(255,255,255,0.03)'; }}
                    onMouseLeave={(e) => { e.currentTarget.style.background = notif.read ? 'transparent' : 'rgba(109,221,255,0.03)'; }}
                  >
                    {/* Icon */}
                    <div style={{
                      width: 36, height: 36, borderRadius: '50%',
                      background: config.bg,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      flexShrink: 0,
                    }}>
                      <Icon size={16} color={config.color} />
                    </div>

                    {/* Content */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <p style={{
                        fontSize: '0.85rem', fontWeight: notif.read ? 400 : 600,
                        marginBottom: '0.15rem',
                        overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                      }}>
                        {notif.title}
                      </p>
                      {notif.content && (
                        <p style={{
                          fontSize: '0.75rem', color: 'var(--on-surface-variant)',
                          overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
                        }}>
                          {notif.content}
                        </p>
                      )}
                      <span style={{ fontSize: '0.65rem', color: 'var(--outline)', marginTop: '0.25rem', display: 'block' }}>
                        {timeAgo(notif.created_at)}
                      </span>
                    </div>

                    {/* Actions */}
                    <div style={{ display: 'flex', gap: '0.25rem', flexShrink: 0 }}>
                      {!notif.read && (
                        <button
                          onClick={(e) => { e.stopPropagation(); markAsRead(notif.id); }}
                          style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--primary)', padding: '0.2rem' }}
                          title="Marcar como leída"
                        >
                          <Check size={14} />
                        </button>
                      )}
                      <button
                        onClick={(e) => { e.stopPropagation(); deleteNotification(notif.id, !notif.read); }}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--on-surface-variant)', padding: '0.2rem' }}
                        title="Eliminar"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>

                    {/* Unread dot */}
                    {!notif.read && (
                      <div style={{
                        width: 8, height: 8, borderRadius: '50%',
                        background: 'var(--primary)',
                        flexShrink: 0, alignSelf: 'center',
                      }} />
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { Search, X, FolderGit2, MessageSquare, User, FileCode, ArrowRight, Command } from 'lucide-react';

interface SearchResult {
  id: string;
  type: 'repo' | 'thread' | 'user' | 'file';
  title: string;
  subtitle: string;
  link: string;
}

interface Props {
  isOpen: boolean;
  onClose: () => void;
}

const typeConfig: Record<string, { icon: React.ElementType; color: string; label: string }> = {
  repo: { icon: FolderGit2, color: 'var(--primary)', label: 'Repositorio' },
  thread: { icon: MessageSquare, color: '#ffb74d', label: 'Foro' },
  user: { icon: User, color: 'var(--secondary)', label: 'Usuario' },
  file: { icon: FileCode, color: 'var(--tertiary)', label: 'Archivo' },
};

export default function SearchModal({ isOpen, onClose }: Props) {
  const router = useRouter();
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const debounceRef = useRef<NodeJS.Timeout | null>(null);

  // Auto-focus on open
  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 100);
      setQuery('');
      setResults([]);
      setSelectedIndex(0);
    }
  }, [isOpen]);

  // Keyboard navigation
  useEffect(() => {
    if (!isOpen) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') { onClose(); return; }
      if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIndex(i => Math.min(i + 1, results.length - 1)); }
      if (e.key === 'ArrowUp') { e.preventDefault(); setSelectedIndex(i => Math.max(i - 1, 0)); }
      if (e.key === 'Enter' && results[selectedIndex]) {
        router.push(results[selectedIndex].link);
        onClose();
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, results, selectedIndex, router, onClose]);

  const performSearch = useCallback(async (q: string) => {
    if (q.length < 2) { setResults([]); return; }
    setLoading(true);

    try {
      const allResults: SearchResult[] = [];

      // Search repositories
      const { data: repos } = await supabase
        .from('repositories')
        .select('id, name, description, primary_language')
        .or(`name.ilike.%${q}%,description.ilike.%${q}%`)
        .limit(5);

      repos?.forEach(r => {
        allResults.push({
          id: `repo-${r.id}`,
          type: 'repo',
          title: r.name,
          subtitle: r.description || r.primary_language || 'Repositorio',
          link: `/repos/${r.id}`,
        });
      });

      // Search forum threads
      const { data: threads } = await supabase
        .from('forum_threads')
        .select('id, title, category')
        .ilike('title', `%${q}%`)
        .limit(5);

      threads?.forEach(t => {
        allResults.push({
          id: `thread-${t.id}`,
          type: 'thread',
          title: t.title,
          subtitle: t.category || 'Foro',
          link: '/forum',
        });
      });

      // Search users/profiles
      const { data: profiles } = await supabase
        .from('profiles')
        .select('id, full_name, role')
        .ilike('full_name', `%${q}%`)
        .limit(5);

      profiles?.forEach(p => {
        const roleLabel = p.role === 'superadministrador' ? 'Admin' : p.role === 'docente' ? 'Docente' : 'Estudiante';
        allResults.push({
          id: `user-${p.id}`,
          type: 'user',
          title: p.full_name || 'Usuario',
          subtitle: roleLabel,
          link: '/profile',
        });
      });

      // Search files by path
      const { data: files } = await supabase
        .from('repository_files')
        .select('id, file_path, repo_id')
        .ilike('file_path', `%${q}%`)
        .limit(5);

      files?.forEach(f => {
        allResults.push({
          id: `file-${f.id}`,
          type: 'file',
          title: f.file_path.split('/').pop() || f.file_path,
          subtitle: f.file_path,
          link: `/repos/${f.repo_id}`,
        });
      });

      setResults(allResults);
      setSelectedIndex(0);
    } catch (err) {
      console.error('[Search] Error:', err);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleInputChange = (value: string) => {
    setQuery(value);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => performSearch(value), 300);
  };

  const handleResultClick = (result: SearchResult) => {
    router.push(result.link);
    onClose();
  };

  if (!isOpen) return null;

  // Group results by type
  const grouped: Record<string, SearchResult[]> = {};
  results.forEach(r => {
    if (!grouped[r.type]) grouped[r.type] = [];
    grouped[r.type].push(r);
  });

  let flatIndex = 0;

  return (
    <div
      className="modal-overlay"
      onClick={onClose}
      style={{ alignItems: 'flex-start', paddingTop: '15vh' }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background: 'var(--surface-container-high)',
          border: '1px solid rgba(72,72,73,0.25)',
          borderRadius: '1rem',
          width: '100%',
          maxWidth: '580px',
          boxShadow: '0 20px 60px rgba(0,0,0,0.6)',
          overflow: 'hidden',
          animation: 'fadeIn 0.15s ease',
        }}
      >
        {/* Search Input */}
        <div style={{
          display: 'flex', alignItems: 'center', gap: '0.75rem',
          padding: '1rem 1.25rem',
          borderBottom: '1px solid rgba(72,72,73,0.15)',
        }}>
          <Search size={20} color="var(--primary)" />
          <input
            ref={inputRef}
            value={query}
            onChange={(e) => handleInputChange(e.target.value)}
            placeholder="Buscar repositorios, archivos, usuarios, foro..."
            style={{
              flex: 1, background: 'transparent', border: 'none', outline: 'none',
              color: 'var(--on-surface)', fontSize: '1rem', fontFamily: 'Inter',
            }}
          />
          {loading && <div className="spinner" style={{ width: 18, height: 18 }} />}
          <kbd style={{
            background: 'var(--surface-bright)', borderRadius: '0.3rem',
            padding: '0.15rem 0.4rem', fontSize: '0.7rem',
            color: 'var(--on-surface-variant)', border: '1px solid rgba(72,72,73,0.3)',
            fontFamily: 'monospace',
          }}>
            ESC
          </kbd>
        </div>

        {/* Results */}
        <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
          {query.length < 2 ? (
            <div style={{ padding: '2.5rem 2rem', textAlign: 'center', color: 'var(--on-surface-variant)' }}>
              <Search size={32} strokeWidth={1} style={{ opacity: 0.3, marginBottom: '0.75rem' }} />
              <p style={{ fontSize: '0.85rem' }}>Escribe al menos 2 caracteres para buscar</p>
              <div style={{ display: 'flex', justifyContent: 'center', gap: '0.5rem', marginTop: '1rem' }}>
                <span style={{ fontSize: '0.7rem', color: 'var(--outline)', display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
                  <kbd style={{ background: 'var(--surface-bright)', padding: '0.1rem 0.3rem', borderRadius: '0.2rem', fontSize: '0.65rem', border: '1px solid rgba(72,72,73,0.3)' }}>↑↓</kbd> navegar
                </span>
                <span style={{ fontSize: '0.7rem', color: 'var(--outline)', display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
                  <kbd style={{ background: 'var(--surface-bright)', padding: '0.1rem 0.3rem', borderRadius: '0.2rem', fontSize: '0.65rem', border: '1px solid rgba(72,72,73,0.3)' }}>↵</kbd> abrir
                </span>
              </div>
            </div>
          ) : results.length === 0 && !loading ? (
            <div style={{ padding: '2.5rem 2rem', textAlign: 'center', color: 'var(--on-surface-variant)' }}>
              <p style={{ fontSize: '0.85rem' }}>No se encontraron resultados para &quot;{query}&quot;</p>
            </div>
          ) : (
            Object.entries(grouped).map(([type, items]) => {
              const config = typeConfig[type] || typeConfig.repo;
              return (
                <div key={type}>
                  {/* Section header */}
                  <div style={{
                    padding: '0.5rem 1.25rem',
                    fontSize: '0.7rem', fontWeight: 600, textTransform: 'uppercase',
                    letterSpacing: '0.05em', color: 'var(--on-surface-variant)',
                    background: 'rgba(72,72,73,0.05)',
                  }}>
                    {config.label}s
                  </div>
                  {items.map(result => {
                    const currentIndex = flatIndex++;
                    const Icon = config.icon;
                    const isSelected = currentIndex === selectedIndex;
                    return (
                      <div
                        key={result.id}
                        onClick={() => handleResultClick(result)}
                        style={{
                          padding: '0.75rem 1.25rem',
                          display: 'flex', alignItems: 'center', gap: '0.75rem',
                          cursor: 'pointer',
                          background: isSelected ? 'rgba(109,221,255,0.08)' : 'transparent',
                          borderLeft: isSelected ? '3px solid var(--primary)' : '3px solid transparent',
                          transition: 'all 0.1s ease',
                        }}
                        onMouseEnter={() => setSelectedIndex(currentIndex)}
                      >
                        <div style={{
                          width: 32, height: 32, borderRadius: '0.5rem',
                          background: config.color + '15',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                          flexShrink: 0,
                        }}>
                          <Icon size={16} color={config.color} />
                        </div>
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <p style={{ fontSize: '0.9rem', fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            {result.title}
                          </p>
                          <p style={{ fontSize: '0.75rem', color: 'var(--on-surface-variant)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                            {result.subtitle}
                          </p>
                        </div>
                        {isSelected && <ArrowRight size={14} color="var(--primary)" />}
                      </div>
                    );
                  })}
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { useAuthStore } from '@/lib/store';
import NotificationBell from '@/components/NotificationBell';
import SearchModal from '@/components/SearchModal';
import {
  LayoutDashboard,
  FolderGit2,
  MessageSquare,
  User,
  LogOut,
  Shield,
  Menu,
  X,
  ChevronLeft,
  Search,
  FileSpreadsheet,
} from 'lucide-react';

export default function Sidebar() {
  const pathname = usePathname();
  const router = useRouter();
  const { user, profile, signOut } = useAuthStore();
  const [isOpen, setIsOpen] = useState(false);
  const [showSearch, setShowSearch] = useState(false);
  const sidebarRef = useRef<HTMLDivElement>(null);

  const handleSignOut = async () => {
    await signOut();
    router.replace('/login');
  };

  // Close on click outside
  const handleClickOutside = useCallback((e: MouseEvent) => {
    if (
      isOpen &&
      sidebarRef.current &&
      !sidebarRef.current.contains(e.target as Node)
    ) {
      setIsOpen(false);
    }
  }, [isOpen]);

  // Close on Escape key
  const handleEscape = useCallback((e: KeyboardEvent) => {
    if (e.key === 'Escape' && isOpen) {
      setIsOpen(false);
    }
  }, [isOpen]);

  useEffect(() => {
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleEscape);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleEscape);
    };
  }, [handleClickOutside, handleEscape]);

  // Ctrl+K to open search
  useEffect(() => {
    const handleCtrlK = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        setShowSearch(true);
      }
    };
    document.addEventListener('keydown', handleCtrlK);
    return () => document.removeEventListener('keydown', handleCtrlK);
  }, []);

  // Close sidebar when navigating to a new page
  useEffect(() => {
    setIsOpen(false);
  }, [pathname]);

  const links = [
    { href: '/dashboard', label: 'Panel Principal', icon: LayoutDashboard },
    { href: '/repos', label: 'Repositorios', icon: FolderGit2 },
    { href: '/forum', label: 'Foro de Dudas', icon: MessageSquare },
    { href: '/profile', label: 'Mi Perfil', icon: User },
  ];

  // Docentes y superadmins pueden ver Reportes
  if (profile?.role === 'docente' || profile?.role === 'superadministrador') {
    links.push({ href: '/reports', label: 'Reportes', icon: FileSpreadsheet });
  }

  // Superadmins ven la sección de administración
  if (profile?.role === 'superadministrador') {
    links.push({ href: '/admin', label: 'Administración', icon: Shield });
  }

  const roleLabel =
    profile?.role === 'superadministrador'
      ? 'Super Administrador'
      : profile?.role === 'docente'
        ? 'Docente'
        : 'Estudiante';

  const roleBgColor =
    profile?.role === 'superadministrador'
      ? 'rgba(255,113,108,0.12)'
      : profile?.role === 'docente'
        ? 'rgba(193,128,255,0.12)'
        : 'rgba(109,221,255,0.12)';

  const roleTextColor =
    profile?.role === 'superadministrador'
      ? 'var(--error)'
      : profile?.role === 'docente'
        ? 'var(--secondary)'
        : 'var(--primary)';

  return (
    <>
      {/* Fixed Top Bar */}
      <div className="topbar glass">
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="sidebar-toggle-btn"
            aria-label={isOpen ? 'Cerrar menú' : 'Abrir menú'}
          >
            {isOpen ? <X size={22} /> : <Menu size={22} />}
          </button>
          <h2 style={{ fontFamily: 'Manrope', fontWeight: 800, fontSize: '1.25rem', color: 'var(--primary)', letterSpacing: '-0.02em', margin: 0 }}>
            AIS<span style={{ color: 'var(--on-surface-variant)', fontWeight: 400 }}> Lab</span>
          </h2>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
          {/* Search button */}
          <button
            onClick={() => setShowSearch(true)}
            className="sidebar-toggle-btn"
            aria-label="Buscar"
            title="Buscar (Ctrl+K)"
          >
            <Search size={18} />
          </button>
          {/* Notifications */}
          {user && <NotificationBell userId={user.id} />}
          {/* Role badge */}
          {profile && (
            <span style={{
              display: 'inline-flex', alignItems: 'center', gap: '0.35rem',
              fontSize: '0.7rem', fontWeight: 600,
              padding: '0.15rem 0.6rem', borderRadius: '9999px',
              background: roleBgColor, color: roleTextColor,
              marginLeft: '0.25rem',
            }}>
              {roleLabel}
            </span>
          )}
        </div>
      </div>

      {/* Search Modal */}
      <SearchModal isOpen={showSearch} onClose={() => setShowSearch(false)} />

      {/* Dark overlay when sidebar is open */}
      <div
        className={`sidebar-overlay ${isOpen ? 'visible' : ''}`}
        aria-hidden={!isOpen}
      />

      {/* Sidebar Panel */}
      <div
        ref={sidebarRef}
        className={`sidebar ${isOpen ? 'open' : ''}`}
        role="navigation"
        aria-label="Menú principal"
      >
        {/* Sidebar Header */}
        <div style={{ padding: '0 1.5rem', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div>
            <h2 style={{ fontFamily: 'Manrope', fontWeight: 800, fontSize: '1.25rem', color: 'var(--primary)', letterSpacing: '-0.02em' }}>
              AIS<span style={{ color: 'var(--on-surface-variant)', fontWeight: 400 }}> Lab</span>
            </h2>
            <p style={{ fontSize: '0.7rem', color: 'var(--on-surface-variant)', marginTop: '0.25rem' }}>
              Plataforma de Aprendizaje
            </p>
          </div>
          <button
            onClick={() => setIsOpen(false)}
            className="sidebar-toggle-btn"
            aria-label="Cerrar menú"
            style={{ marginRight: '-0.5rem' }}
          >
            <ChevronLeft size={20} />
          </button>
        </div>

        {/* Navigation Links */}
        <nav style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
          {links.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className={`sidebar-link ${pathname === link.href ? 'active' : ''}`}
            >
              <link.icon size={18} />
              {link.label}
            </Link>
          ))}
        </nav>

        {/* Footer: user info + logout */}
        <div style={{ padding: '1rem 1.5rem', borderTop: '1px solid rgba(72,72,73,0.15)' }}>
          {profile && (
            <div style={{ marginBottom: '0.75rem' }}>
              <p style={{ fontSize: '0.85rem', fontWeight: 600, marginBottom: '0.25rem' }}>
                {profile.full_name || 'Usuario'}
              </p>
              <span style={{
                display: 'inline-block',
                fontSize: '0.7rem',
                fontWeight: 600,
                padding: '0.15rem 0.5rem',
                borderRadius: '9999px',
                background: roleBgColor,
                color: roleTextColor,
              }}>
                {roleLabel}
              </span>
            </div>
          )}
          <button
            onClick={handleSignOut}
            style={{
              display: 'flex', alignItems: 'center', gap: '0.5rem',
              color: 'var(--on-surface-variant)', background: 'none',
              border: 'none', cursor: 'pointer', fontSize: '0.8rem',
              fontFamily: 'Inter', padding: '0.25rem 0',
              transition: 'color 0.15s',
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = 'var(--error)')}
            onMouseLeave={(e) => (e.currentTarget.style.color = 'var(--on-surface-variant)')}
          >
            <LogOut size={16} />
            Cerrar Sesión
          </button>
        </div>
      </div>
    </>
  );
}
